 20→@Service
 21→public class ContentStandardizationService {
 22→    private static final Logger logger = LoggerFactory.getLogger(ContentStandardizationService.class);
 23→    private final StandardizedContentRecordRepository contentRepository;
 24→    private final MediaMetadataRepository mediaMetadataRepository;
 25→    private final UserRepository userRepository;
 26→    private final TimestampNormalizer timestampNormalizer;
 27→    private final AddressNormalizer addressNormalizer;
 28→    private final LanguageDetector languageDetector;
 29→    private final AuditLogService auditLogService;
 30→    private final ObjectMapper objectMapper;
 31→
 32→    public ContentStandardizationService(StandardizedContentRecordRepository contentRepository,
 33→            MediaMetadataRepository mediaMetadataRepository, UserRepository userRepository,
 34→            TimestampNormalizer timestampNormalizer, AddressNormalizer addressNormalizer,
 35→            LanguageDetector languageDetector, AuditLogService auditLogService, ObjectMapper objectMapper) {
 36→        this.contentRepository = contentRepository;
 37→        this.mediaMetadataRepository = mediaMetadataRepository;
 38→        this.userRepository = userRepository;
 39→        this.timestampNormalizer = timestampNormalizer;
 40→        this.addressNormalizer = addressNormalizer;
 41→        this.languageDetector = languageDetector;
 42→        this.auditLogService = auditLogService;
 43→        this.objectMapper = objectMapper;
 44→    }
 45→
 46→    @Transactional
 47→    public StandardizedContentRecord standardize(Map<String, Object> rawData, String timezoneId,
 48→            CrawlRun crawlRun, CrawlSourceProfile source) {
 49→        StandardizedContentRecord record = new StandardizedContentRecord();
 50→        record.setCrawlRun(crawlRun);
 51→        record.setSourceProfile(source);
 52→        record.setTitle(getStringValue(rawData, "title", "Untitled"));
 53→        record.setDescription(getStringValue(rawData, "description", null));
 54→        record.setBodyText(getStringValue(rawData, "bodyText", null));
 55→        record.setContentType(getStringValue(rawData, "contentType", "article"));
 56→        record.setSourceUrl(getStringValue(rawData, "sourceUrl", null));
 57→
 58→        String rawTimestamp = getStringValue(rawData, "timestamp", null);
 59→        if (rawTimestamp != null && timezoneId != null) {
 60→            record.setStandardizedTimestamp(timestampNormalizer.normalize(rawTimestamp, timezoneId));
 61→            record.setTimezoneId(timezoneId);
 62→        }
 63→
 64→        String rawLocation = getStringValue(rawData, "location", null);
 65→        if (rawLocation != null) {
 66→            record.setOriginalLocation(rawLocation);
 67→            record.setNormalizedAddress(addressNormalizer.normalize(rawLocation));
 68→        }
 69→
 70→        String textForLang = record.getBodyText() != null ? record.getBodyText() : record.getTitle();
 71→        record.setDetectedLanguage(languageDetector.detect(textForLang));
 72→
 73→        if (rawData.containsKey("price")) {
 74→            try {
 75→                record.setPrice(new java.math.BigDecimal(rawData.get("price").toString()));
 76→            } catch (NumberFormatException ignored) {}
 77→        }
 78→
 79→        return contentRepository.save(record);
 80→    }
 81→
 82→    public Page<StandardizedContentRecord> listContent(Pageable pageable) {
 83→        return contentRepository.findAll(pageable);
 84→    }
 85→
 86→    public StandardizedContentRecord getContentById(Long id) {
 87→        return contentRepository.findById(id)
 88→                .orElseThrow(() -> new com.scholarops.exception.ResourceNotFoundException("Content not found: " + id));
 89→    }
 90→
 91→    public List<MediaMetadata> getMediaMetadata(Long contentId) {
 92→        return mediaMetadataRepository.findByContentRecordId(contentId);
 93→    }
 94→
 95→    @Transactional
 96→    public void publishContent(List<Long> contentIds, Long userId) {
 97→        User publisher = userRepository.findById(userId).orElseThrow();
 98→        for (Long id : contentIds) {
 99→            StandardizedContentRecord record = contentRepository.findById(id).orElseThrow(
100→                    () -> new com.scholarops.exception.ResourceNotFoundException("Content not found: " + id));
101→            record.setIsPublished(true);
102→            record.setPublishedAt(LocalDateTime.now());
103→            record.setPublishedBy(publisher);
104→            contentRepository.save(record);
105→            auditLogService.log(userId, AuditAction.CONTENT_PUBLISH, "StandardizedContentRecord", id,
106→                    "Published content: " + record.getTitle(), null, null);
107→        }
108→    }
109→
110→    private String getStringValue(Map<String, Object> data, String key, String defaultValue) {
111→        Object value = data.get(key);
112→        return value != null ? value.toString() : defaultValue;
113→    }
114→}
