  1→package com.scholarops.util;
  2→
  3→import java.util.*;
  4→
  5→public final class FingerprintUtil {
  6→
  7→    private FingerprintUtil() {
  8→        // Utility class
  9→    }
 10→
 11→    /**
 12→     * Generates a set of fingerprint hashes from text using the winnowing algorithm.
 13→     *
 14→     * @param text       the input text
 15→     * @param ngramSize  the size of character n-grams (k-grams)
 16→     * @param windowSize the window size for winnowing selection
 17→     * @return a set of selected fingerprint hash values
 18→     */
 19→    public static Set<Long> generateFingerprint(String text, int ngramSize, int windowSize) {
 20→        String normalized = normalizeText(text);
 21→        if (normalized.length() < ngramSize) {
 22→            return Collections.emptySet();
 23→        }
 24→
 25→        // Generate k-gram hashes
 26→        List<Long> kgramHashes = new ArrayList<>();
 27→        for (int i = 0; i <= normalized.length() - ngramSize; i++) {
 28→            String kgram = normalized.substring(i, i + ngramSize);
 29→            kgramHashes.add(hashKgram(kgram));
 30→        }
 31→
 32→        // Apply winnowing: select minimum hash from each window
 33→        Set<Long> fingerprints = new LinkedHashSet<>();
 34→        if (kgramHashes.size() < windowSize) {
 35→            // If fewer hashes than window size, pick the minimum
 36→            kgramHashes.stream().min(Long::compareTo).ifPresent(fingerprints::add);
 37→            return fingerprints;
 38→        }
 39→
 40→        long previousMin = Long.MAX_VALUE;
 41→        int previousMinIndex = -1;
 42→
 43→        for (int i = 0; i <= kgramHashes.size() - windowSize; i++) {
 44→            int windowEnd = i + windowSize;
 45→
 46→            // If previous minimum is still in the window, only check the new element
 47→            if (previousMinIndex >= i && previousMinIndex < windowEnd) {
 48→                long newElement = kgramHashes.get(windowEnd - 1);
 49→                if (newElement <= previousMin) {
 50→                    previousMin = newElement;
 51→                    previousMinIndex = windowEnd - 1;
 52→                    fingerprints.add(previousMin);
 53→                } else {
 54→                    fingerprints.add(previousMin);
 55→                }
 56→            } else {
 57→                // Scan the entire window for the rightmost minimum
 58→                long windowMin = Long.MAX_VALUE;
 59→                int windowMinIndex = i;
 60→                for (int j = i; j < windowEnd; j++) {
 61→                    if (kgramHashes.get(j) <= windowMin) {
 62→                        windowMin = kgramHashes.get(j);
 63→                        windowMinIndex = j;
 64→                    }
 65→                }
 66→                previousMin = windowMin;
 67→                previousMinIndex = windowMinIndex;
 68→                fingerprints.add(windowMin);
 69→            }
 70→        }
 71→
 72→        return fingerprints;
 73→    }
 74→
 75→    /**
 76→     * Computes the Jaccard similarity between two fingerprint sets.
 77→     *
 78→     * @param fp1 first fingerprint set
 79→     * @param fp2 second fingerprint set
 80→     * @return Jaccard similarity coefficient between 0.0 and 1.0
 81→     */
 82→    public static double computeSimilarity(Set<Long> fp1, Set<Long> fp2) {
 83→        if (fp1 == null || fp2 == null || (fp1.isEmpty() && fp2.isEmpty())) {
 84→            return 0.0;
 85→        }
 86→        if (fp1.isEmpty() || fp2.isEmpty()) {
 87→            return 0.0;
 88→        }
 89→
 90→        Set<Long> intersection = new HashSet<>(fp1);
 91→        intersection.retainAll(fp2);
 92→
 93→        Set<Long> union = new HashSet<>(fp1);
 94→        union.addAll(fp2);
 95→
 96→        return (double) intersection.size() / union.size();
 97→    }
 98→
 99→    /**
100→     * Normalizes text by removing all whitespace and converting to lowercase.
101→     *
102→     * @param text the input text
103→     * @return normalized text
104→     */
105→    public static String normalizeText(String text) {
106→        if (text == null) {
107→            return "";
108→        }
109→        return text.replaceAll("\\s+", "").toLowerCase();
110→    }
111→
112→    public static String hashText(String text) {
113→        String normalized = normalizeText(text);
114→        return Long.toHexString(hashKgram(normalized));
115→    }
116→
117→    private static long hashKgram(String kgram) {
118→        // Use a rolling hash based on a large prime
119→        long hash = 0;
120→        long base = 31;
121→        long mod = 1_000_000_007L;
122→        for (int i = 0; i < kgram.length(); i++) {
123→            hash = (hash * base + kgram.charAt(i)) % mod;
124→        }
125→        return hash;
126→    }
127→}
