 1→package com.scholarops.crawler;
 2→
 3→import java.util.concurrent.ConcurrentHashMap;
 4→import java.util.concurrent.atomic.AtomicLong;
 5→
 6→public class RateLimiter {
 7→
 8→    private final ConcurrentHashMap<Long, TokenBucket> buckets = new ConcurrentHashMap<>();
 9→    private final int defaultRatePerMinute;
10→
11→    public RateLimiter(int defaultRatePerMinute) {
12→        this.defaultRatePerMinute = defaultRatePerMinute;
13→    }
14→
15→    public boolean tryAcquire(Long sourceId, int ratePerMinute) {
16→        int rate = ratePerMinute > 0 ? ratePerMinute : defaultRatePerMinute;
17→        TokenBucket bucket = buckets.computeIfAbsent(sourceId, k -> new TokenBucket(rate));
18→        return bucket.tryConsume();
19→    }
20→
21→    public void reset(Long sourceId) {
22→        buckets.remove(sourceId);
23→    }
24→
25→    private static class TokenBucket {
26→        private final int maxTokens;
27→        private final AtomicLong availableTokens;
28→        private volatile long lastRefillTimestamp;
29→        private final double refillRate;
30→
31→        TokenBucket(int tokensPerMinute) {
32→            this.maxTokens = tokensPerMinute;
33→            this.availableTokens = new AtomicLong(tokensPerMinute);
34→            this.lastRefillTimestamp = System.nanoTime();
35→            this.refillRate = tokensPerMinute / 60.0;
36→        }
37→
38→        synchronized boolean tryConsume() {
39→            refill();
40→            long current = availableTokens.get();
41→            if (current > 0) {
42→                availableTokens.decrementAndGet();
43→                return true;
44→            }
45→            return false;
46→        }
47→
48→        private void refill() {
49→            long now = System.nanoTime();
50→            double elapsed = (now - lastRefillTimestamp) / 1_000_000_000.0;
51→            long tokensToAdd = (long) (elapsed * refillRate);
52→            if (tokensToAdd > 0) {
53→                long newTokens = Math.min(maxTokens, availableTokens.get() + tokensToAdd);
54→                availableTokens.set(newTokens);
55→                lastRefillTimestamp = now;
56→            }
57→        }
58→    }
59→}
