  1→package com.scholarops.security;
  2→
  3→import io.jsonwebtoken.*;
  4→import io.jsonwebtoken.security.Keys;
  5→import org.slf4j.Logger;
  6→import org.slf4j.LoggerFactory;
  7→import org.springframework.beans.factory.annotation.Value;
  8→import org.springframework.security.core.Authentication;
  9→import org.springframework.security.core.GrantedAuthority;
 10→import org.springframework.stereotype.Component;
 11→
 12→import javax.crypto.SecretKey;
 13→import java.util.Base64;
 14→import java.util.Date;
 15→import java.util.stream.Collectors;
 16→
 17→@Component
 18→public class JwtTokenProvider {
 19→
 20→    private static final Logger logger = LoggerFactory.getLogger(JwtTokenProvider.class);
 21→
 22→    private final SecretKey key;
 23→    private final long jwtExpirationMs;
 24→    private final long refreshExpirationMs;
 25→
 26→    public JwtTokenProvider(
 27→            @Value("${scholarops.jwt.secret}") String jwtSecret,
 28→            @Value("${scholarops.jwt.expiration-ms}") long jwtExpirationMs,
 29→            @Value("${scholarops.jwt.refresh-expiration-ms}") long refreshExpirationMs) {
 30→        byte[] keyBytes = Base64.getDecoder().decode(jwtSecret);
 31→        this.key = Keys.hmacShaKeyFor(keyBytes);
 32→        this.jwtExpirationMs = jwtExpirationMs;
 33→        this.refreshExpirationMs = refreshExpirationMs;
 34→    }
 35→
 36→    public String generateAccessToken(Authentication authentication) {
 37→        UserDetailsImpl userDetails = (UserDetailsImpl) authentication.getPrincipal();
 38→        Date now = new Date();
 39→        Date expiryDate = new Date(now.getTime() + jwtExpirationMs);
 40→
 41→        String roles = userDetails.getAuthorities().stream()
 42→                .map(GrantedAuthority::getAuthority)
 43→                .collect(Collectors.joining(","));
 44→
 45→        return Jwts.builder()
 46→                .subject(userDetails.getId().toString())
 47→                .claim("username", userDetails.getUsername())
 48→                .claim("roles", roles)
 49→                .issuedAt(now)
 50→                .expiration(expiryDate)
 51→                .signWith(key)
 52→                .compact();
 53→    }
 54→
 55→    public String generateRefreshToken(Long userId) {
 56→        Date now = new Date();
 57→        Date expiryDate = new Date(now.getTime() + refreshExpirationMs);
 58→
 59→        return Jwts.builder()
 60→                .subject(userId.toString())
 61→                .claim("type", "refresh")
 62→                .issuedAt(now)
 63→                .expiration(expiryDate)
 64→                .signWith(key)
 65→                .compact();
 66→    }
 67→
 68→    public Long getUserIdFromToken(String token) {
 69→        Claims claims = Jwts.parser()
 70→                .verifyWith(key)
 71→                .build()
 72→                .parseSignedClaims(token)
 73→                .getPayload();
 74→        return Long.parseLong(claims.getSubject());
 75→    }
 76→
 77→    public String getUsernameFromToken(String token) {
 78→        Claims claims = Jwts.parser()
 79→                .verifyWith(key)
 80→                .build()
 81→                .parseSignedClaims(token)
 82→                .getPayload();
 83→        return claims.get("username", String.class);
 84→    }
 85→
 86→    public boolean validateToken(String token) {
 87→        try {
 88→            Jwts.parser().verifyWith(key).build().parseSignedClaims(token);
 89→            return true;
 90→        } catch (MalformedJwtException e) {
 91→            logger.warn("Invalid JWT token");
 92→        } catch (ExpiredJwtException e) {
 93→            logger.warn("Expired JWT token");
 94→        } catch (UnsupportedJwtException e) {
 95→            logger.warn("Unsupported JWT token");
 96→        } catch (IllegalArgumentException e) {
 97→            logger.warn("JWT claims string is empty");
 98→        }
 99→        return false;
100→    }
101→
102→    public long getExpirationMs() {
103→        return jwtExpirationMs;
104→    }
105→}
