 18→
 19→@Service
 20→public class GradingWorkflowService {
 21→    private final GradingStateRepository gradingStateRepository;
 22→    private final RubricScoreRepository rubricScoreRepository;
 23→    private final SubmissionAnswerRepository answerRepository;
 24→    private final AuditLogService auditLogService;
 25→
 26→    public GradingWorkflowService(GradingStateRepository gradingStateRepository,
 27→            RubricScoreRepository rubricScoreRepository, SubmissionAnswerRepository answerRepository,
 28→            AuditLogService auditLogService) {
 29→        this.gradingStateRepository = gradingStateRepository;
 30→        this.rubricScoreRepository = rubricScoreRepository;
 31→        this.answerRepository = answerRepository;
 32→        this.auditLogService = auditLogService;
 33→    }
 34→
 35→    @Transactional
 36→    public void routeToQueue(SubmissionAnswer answer) {
 37→        GradingState state = GradingState.builder()
 38→                .submissionAnswer(answer).status("PENDING").build();
 39→        gradingStateRepository.save(state);
 40→    }
 41→
 42→    public Page<GradingState> getGradingQueue(Pageable pageable, String status) {
 43→        return gradingStateRepository.findByStatus(status, pageable);
 44→    }
 45→
 46→    public GradingState getGradingState(Long id) {
 47→        return gradingStateRepository.findById(id)
 48→                .orElseThrow(() -> new ResourceNotFoundException("Grading state not found: " + id));
 49→    }
 50→
 51→    @Transactional
 52→    public GradingState gradeItem(Long gradingStateId, GradingRequest request, Long graderId) {
 53→        GradingState state = getGradingState(gradingStateId);
 54→        state.setScore(request.getScore() != null ? BigDecimal.valueOf(request.getScore()) : null);
 55→        state.setFeedback(request.getFeedback());
 56→        state.setStatus("GRADED");
 57→        state.setGradedAt(LocalDateTime.now());
 58→
 59→        SubmissionAnswer answer = state.getSubmissionAnswer();
 60→        answer.setScore(request.getScore() != null ? BigDecimal.valueOf(request.getScore()) : null);
 61→        answer.setGradedAt(LocalDateTime.now());
 62→        answerRepository.save(answer);
 63→
 64→        auditLogService.log(graderId, AuditAction.GRADING_SUBMIT, "GradingState", gradingStateId,
 65→                "Graded submission answer", null, null);
 66→        return gradingStateRepository.save(state);
 67→    }
 68→
 69→    @Transactional
 70→    public GradingState addRubricScores(Long gradingStateId, List<RubricScoreRequest> rubricScores, Long graderId) {
 71→        GradingState state = getGradingState(gradingStateId);
 72→        if (rubricScores == null || rubricScores.isEmpty()) {
 73→            throw new IllegalArgumentException("Rubric scores are mandatory for subjective grading");
 74→        }
 75→
 76→        BigDecimal totalAwarded = BigDecimal.ZERO;
 77→        for (RubricScoreRequest scoreReq : rubricScores) {
 78→            RubricScore rubric = RubricScore.builder()
 79→                    .gradingState(state)
 80→                    .criterionName(scoreReq.getCriterionName())
 81→                    .maxScore(BigDecimal.valueOf(scoreReq.getMaxScore()))
 82→                    .awardedScore(BigDecimal.valueOf(scoreReq.getAwardedScore()))
 83→                    .comment(scoreReq.getComment())
 84→                    .build();
 85→            rubricScoreRepository.save(rubric);
 86→            totalAwarded = totalAwarded.add(BigDecimal.valueOf(scoreReq.getAwardedScore()));
 87→        }
 88→
 89→        state.setScore(totalAwarded);
 90→        state.setStatus("GRADED");
 91→        state.setGradedAt(LocalDateTime.now());
 92→
 93→        SubmissionAnswer answer = state.getSubmissionAnswer();
 94→        answer.setScore(totalAwarded);
 95→        answer.setGradedAt(LocalDateTime.now());
 96→        answerRepository.save(answer);
 97→
 98→        auditLogService.log(graderId, AuditAction.GRADING_SUBMIT, "GradingState", gradingStateId,
 99→                "Added rubric scores", null, null);
100→        return gradingStateRepository.save(state);
101→    }
102→}
