  1→package com.scholarops.service;
  2→
  3→import com.scholarops.exception.ForbiddenException;
  4→import com.scholarops.exception.ResourceNotFoundException;
  5→import com.scholarops.model.dto.QuizAssemblyRequest;
  6→import com.scholarops.model.dto.QuizRuleDto;
  7→import com.scholarops.model.entity.*;
  8→import com.scholarops.model.enums.AuditAction;
  9→import com.scholarops.repository.*;
 10→import org.springframework.stereotype.Service;
 11→import org.springframework.transaction.annotation.Transactional;
 12→
 13→import java.math.BigDecimal;
 14→import java.time.LocalDateTime;
 15→import java.util.*;
 16→import java.util.stream.Collectors;
 17→
 18→@Service
 19→public class QuizAssemblyService {
 20→    private final QuizPaperRepository quizPaperRepository;
 21→    private final QuestionRepository questionRepository;
 22→    private final QuestionBankRepository questionBankRepository;
 23→    private final QuizRuleRepository quizRuleRepository;
 24→    private final UserRepository userRepository;
 25→    private final AuditLogService auditLogService;
 26→
 27→    public QuizAssemblyService(QuizPaperRepository quizPaperRepository, QuestionRepository questionRepository,
 28→            QuestionBankRepository questionBankRepository, QuizRuleRepository quizRuleRepository,
 29→            UserRepository userRepository, AuditLogService auditLogService) {
 30→        this.quizPaperRepository = quizPaperRepository;
 31→        this.questionRepository = questionRepository;
 32→        this.questionBankRepository = questionBankRepository;
 33→        this.quizRuleRepository = quizRuleRepository;
 34→        this.userRepository = userRepository;
 35→        this.auditLogService = auditLogService;
 36→    }
 37→
 38→    @Transactional
 39→    public QuizPaper assembleQuiz(QuizAssemblyRequest request, Long userId) {
 40→        QuestionBank bank = questionBankRepository.findById(request.getQuestionBankId())
 41→                .orElseThrow(() -> new ResourceNotFoundException("Question bank not found"));
 42→        User user = userRepository.findById(userId).orElseThrow();
 43→
 44→        Set<Question> selectedQuestions = new LinkedHashSet<>();
 45→        List<Question> allBankQuestions = questionRepository.findByQuestionBankId(bank.getId());
 46→
 47→        if (request.getRules() != null) {
 48→            for (QuizRuleDto rule : request.getRules()) {
 49→                if ("DIFFICULTY".equals(rule.getRuleType()) && rule.getDifficultyLevel() != null) {
 50→                    List<Question> matching = allBankQuestions.stream()
 51→                            .filter(q -> q.getDifficultyLevel().equals(rule.getDifficultyLevel()))
 52→                            .filter(q -> !selectedQuestions.contains(q))
 53→                            .collect(Collectors.toList());
 54→                    int needed = rule.getMinCount() != null ? rule.getMinCount() : 0;
 55→                    if (matching.size() < needed) {
 56→                        throw new IllegalArgumentException("Not enough questions with difficulty " +
 57→                                rule.getDifficultyLevel() + ": need " + needed + " but only " + matching.size() + " available");
 58→                    }
 59→                    Collections.shuffle(matching);
 60→                    selectedQuestions.addAll(matching.subList(0, Math.min(needed, matching.size())));
 61→                }
 62→            }
 63→        }
 64→
 65→        List<Question> remaining = allBankQuestions.stream()
 66→                .filter(q -> !selectedQuestions.contains(q))
 67→                .collect(Collectors.toList());
 68→        Collections.shuffle(remaining);
 69→        int totalNeeded = request.getTotalQuestions();
 70→        while (selectedQuestions.size() < totalNeeded && !remaining.isEmpty()) {
 71→            selectedQuestions.add(remaining.remove(0));
 72→        }
 73→
 74→        if (selectedQuestions.size() < totalNeeded) {
 75→            throw new IllegalArgumentException("Not enough questions: need " + totalNeeded +
 76→                    " but only " + selectedQuestions.size() + " available after applying rules");
 77→        }
 78→
 79→        BigDecimal totalPoints = selectedQuestions.stream()
 80→                .map(Question::getPoints).reduce(BigDecimal.ZERO, BigDecimal::add);
 81→
 82→        QuizPaper quiz = QuizPaper.builder()
 83→                .title(request.getTitle())
 84→                .description(request.getDescription())
 85→                .questionBank(bank)
 86→                .totalQuestions(selectedQuestions.size())
 87→                .totalPoints(totalPoints)
 88→                .timeLimitMinutes(request.getTimeLimitMinutes())
 89→                .maxAttempts(request.getMaxAttempts() != null ? request.getMaxAttempts() : 1)
 90→                .releaseStart(request.getReleaseStart())
 91→                .releaseEnd(request.getReleaseEnd())
 92→                .shuffleQuestions(request.getShuffleQuestions() != null && request.getShuffleQuestions())
 93→                .showImmediateFeedback(request.getShowImmediateFeedback() == null || request.getShowImmediateFeedback())
 94→                .createdBy(user)
 95→                .questions(new ArrayList<>(selectedQuestions))
 96→                .build();
 97→
 98→        quiz = quizPaperRepository.save(quiz);
 99→
100→        if (request.getRules() != null) {
101→            for (QuizRuleDto ruleDto : request.getRules()) {
102→                QuizRule rule = QuizRule.builder()
103→                        .quizPaper(quiz).ruleType(ruleDto.getRuleType())
104→                        .minCount(ruleDto.getMinCount()).maxCount(ruleDto.getMaxCount())
105→                        .difficultyLevel(ruleDto.getDifficultyLevel()).build();
106→                quizRuleRepository.save(rule);
107→            }
108→        }
109→
110→        auditLogService.log(userId, AuditAction.QUIZ_CREATE, "QuizPaper", quiz.getId(),
111→                "Assembled quiz: " + quiz.getTitle() + " with " + selectedQuestions.size() + " questions", null, null);
112→        return quiz;
113→    }
114→
115→    public QuizPaper getQuiz(Long id) {
116→        return quizPaperRepository.findById(id)
117→                .orElseThrow(() -> new ResourceNotFoundException("Quiz not found: " + id));
118→    }
119→
120→    public List<QuizPaper> listQuizzes(Long userId) {
121→        return quizPaperRepository.findByCreatedById(userId);
122→    }
123→
124→    @Transactional
125→    public QuizPaper scheduleQuiz(Long id, LocalDateTime releaseStart, LocalDateTime releaseEnd, Long userId) {
126→        QuizPaper quiz = getQuiz(id);
127→        if (!quiz.getCreatedBy().getId().equals(userId)) throw new ForbiddenException("Not authorized");
128→        quiz.setReleaseStart(releaseStart);
129→        quiz.setReleaseEnd(releaseEnd);
130→        auditLogService.log(userId, AuditAction.QUIZ_SCHEDULE, "QuizPaper", id, "Scheduled quiz release window", null, null);
131→        return quizPaperRepository.save(quiz);
132→    }
133→
134→    @Transactional
135→    public QuizPaper publishQuiz(Long id, Long userId) {
136→        QuizPaper quiz = getQuiz(id);
137→        if (!quiz.getCreatedBy().getId().equals(userId)) throw new ForbiddenException("Not authorized");
138→        quiz.setIsPublished(true);
139→        auditLogService.log(userId, AuditAction.QUIZ_PUBLISH, "QuizPaper", id, "Published quiz", null, null);
140→        return quizPaperRepository.save(quiz);
141→    }
142→}
