 52→        CrawlSourceProfile savedProfile = crawlSourceProfileRepository.save(profile);
 53→
 54→        // Encrypt and store credentials if provided
 55→        if (hasCredentials(request)) {
 56→            encryptAndSaveCredentials(savedProfile, request);
 57→        }
 58→
 59→        auditLogService.log(
 60→                userId,
 61→                AuditAction.CRAWL_SOURCE_CREATE,
 62→                "CrawlSourceProfile",
 63→                savedProfile.getId(),
 64→                "Created crawl source: " + savedProfile.getName(),
 65→                null,
 66→                null
 67→        );
 68→
 69→        logger.info("Crawl source '{}' created by userId={}", savedProfile.getName(), userId);
 70→        return savedProfile;
 71→    }
 72→
 73→    @Transactional
 74→    public CrawlSourceProfile updateSource(Long id, CrawlSourceRequest request, Long userId) {
 75→        CrawlSourceProfile profile = crawlSourceProfileRepository.findById(id)
 76→                .orElseThrow(() -> new ResourceNotFoundException("CrawlSourceProfile", "id", id));
 77→
 78→        verifyOwnership(profile, userId);
 79→
 80→        profile.setName(request.getName());
 81→        profile.setBaseUrl(request.getBaseUrl());
 82→        profile.setDescription(request.getDescription());
 83→        if (request.getRateLimitPerMinute() != null) {
 84→            profile.setRateLimitPerMinute(request.getRateLimitPerMinute());
 85→        }
 86→        if (request.getRequiresAuth() != null) {
 87→            profile.setRequiresAuth(request.getRequiresAuth());
 88→        }
 89→
 90→        // Re-encrypt credentials if provided
 91→        if (hasCredentials(request)) {
 92→            // Remove existing credentials if present
 93→            if (profile.getCredential() != null) {
 94→                encryptedSourceCredentialRepository.delete(profile.getCredential());
 95→                profile.setCredential(null);
 96→            }
 97→            encryptAndSaveCredentials(profile, request);
 98→        }
 99→
100→        CrawlSourceProfile updatedProfile = crawlSourceProfileRepository.save(profile);
101→
102→        auditLogService.log(
103→                userId,
104→                AuditAction.CRAWL_SOURCE_UPDATE,
105→                "CrawlSourceProfile",
106→                id,
107→                "Updated crawl source: " + profile.getName(),
108→                null,
109→                null
110→        );
111→
112→        logger.info("Crawl source '{}' updated by userId={}", profile.getName(), userId);
