156→
157→    private void verifyOwnership(CrawlSourceProfile profile, Long userId) {
158→        if (!profile.getCreatedBy().getId().equals(userId)) {
159→            throw new ForbiddenException("You do not have permission to access this crawl source");
160→        }
161→    }
162→
163→    private boolean hasCredentials(CrawlSourceRequest request) {
164→        return (request.getUsername() != null && !request.getUsername().isBlank())
165→                || (request.getPassword() != null && !request.getPassword().isBlank())
166→                || (request.getApiKey() != null && !request.getApiKey().isBlank());
167→    }
168→
169→    private void encryptAndSaveCredentials(CrawlSourceProfile profile, CrawlSourceRequest request) {
170→        // Use a single IV for all credential fields of this source
171→        byte[] iv = null;
172→        byte[] encryptedUsername = null;
173→        byte[] encryptedPassword = null;
174→        byte[] encryptedApiKey = null;
175→
176→        if (request.getUsername() != null && !request.getUsername().isBlank()) {
177→            AesEncryptionUtil.EncryptedData data = encryptionService.encrypt(request.getUsername());
178→            encryptedUsername = data.getCiphertext();
179→            iv = data.getIv();
180→        }
181→
182→        if (request.getPassword() != null && !request.getPassword().isBlank()) {
183→            AesEncryptionUtil.EncryptedData data = encryptionService.encrypt(request.getPassword());
184→            encryptedPassword = data.getCiphertext();
185→            if (iv == null) {
186→                iv = data.getIv();
187→            }
188→        }
189→
190→        if (request.getApiKey() != null && !request.getApiKey().isBlank()) {
191→            AesEncryptionUtil.EncryptedData data = encryptionService.encrypt(request.getApiKey());
192→            encryptedApiKey = data.getCiphertext();
193→            if (iv == null) {
194→                iv = data.getIv();
195→            }
196→        }
197→
198→        if (iv != null) {
199→            EncryptedSourceCredential credential = EncryptedSourceCredential.builder()
200→                    .sourceProfile(profile)
201→                    .encryptedUsername(encryptedUsername)
202→                    .encryptedPassword(encryptedPassword)
203→                    .encryptedApiKey(encryptedApiKey)
204→                    .encryptionIv(iv)
205→                    .build();
206→            encryptedSourceCredentialRepository.save(credential);
207→            profile.setCredential(credential);
208→        }
209→    }
210→}
