  1→package com.scholarops.service;
  2→
  3→import com.scholarops.exception.ResourceNotFoundException;
  4→import com.scholarops.model.entity.*;
  5→import com.scholarops.repository.*;
  6→import com.scholarops.util.FingerprintUtil;
  7→import org.slf4j.Logger;
  8→import org.slf4j.LoggerFactory;
  9→import org.springframework.beans.factory.annotation.Value;
 10→import org.springframework.stereotype.Service;
 11→import org.springframework.transaction.annotation.Transactional;
 12→
 13→import java.math.BigDecimal;
 14→import java.time.LocalDateTime;
 15→import java.util.List;
 16→import java.util.Set;
 17→
 18→@Service
 19→public class PlagiarismService {
 20→    private static final Logger logger = LoggerFactory.getLogger(PlagiarismService.class);
 21→    private final PlagiarismCheckRepository checkRepository;
 22→    private final PlagiarismMatchRepository matchRepository;
 23→    private final SubmissionRepository submissionRepository;
 24→    private final SubmissionAnswerRepository answerRepository;
 25→    private final StandardizedContentRecordRepository contentRepository;
 26→
 27→    @Value("${scholarops.plagiarism.similarity-threshold:0.85}")
 28→    private double similarityThreshold;
 29→
 30→    @Value("${scholarops.plagiarism.ngram-size:5}")
 31→    private int ngramSize;
 32→
 33→    @Value("${scholarops.plagiarism.window-size:4}")
 34→    private int windowSize;
 35→
 36→    public PlagiarismService(PlagiarismCheckRepository checkRepository, PlagiarismMatchRepository matchRepository,
 37→            SubmissionRepository submissionRepository, SubmissionAnswerRepository answerRepository,
 38→            StandardizedContentRecordRepository contentRepository) {
 39→        this.checkRepository = checkRepository;
 40→        this.matchRepository = matchRepository;
 41→        this.submissionRepository = submissionRepository;
 42→        this.answerRepository = answerRepository;
 43→        this.contentRepository = contentRepository;
 44→    }
 45→
 46→    @Transactional
 47→    public PlagiarismCheck checkSubmission(Submission submission) {
 48→        PlagiarismCheck check = PlagiarismCheck.builder().submission(submission).status("RUNNING").build();
 49→        check = checkRepository.save(check);
 50→
 51→        String submissionText = buildSubmissionText(submission);
 52→        Set<Long> sourceFingerprint = FingerprintUtil.generateFingerprint(submissionText, ngramSize, windowSize);
 53→
 54→        double maxSimilarity = 0.0;
 55→
 56→        List<Submission> priorSubmissions = submissionRepository.findByQuizPaperId(
 57→                submission.getQuizPaper().getId());
 58→        for (Submission prior : priorSubmissions) {
 59→            if (prior.getId().equals(submission.getId())) continue;
 60→            String priorText = buildSubmissionText(prior);
 61→            Set<Long> priorFp = FingerprintUtil.generateFingerprint(priorText, ngramSize, windowSize);
 62→            double similarity = FingerprintUtil.computeSimilarity(sourceFingerprint, priorFp);
 63→
 64→            if (similarity >= similarityThreshold) {
 65→                PlagiarismMatch match = PlagiarismMatch.builder()
 66→                        .plagiarismCheck(check).matchedSubmission(prior)
 67→                        .similarityScore(BigDecimal.valueOf(similarity))
 68→                        .matchedTextExcerpt(priorText.substring(0, Math.min(200, priorText.length())))
 69→                        .sourceTextExcerpt(submissionText.substring(0, Math.min(200, submissionText.length())))
 70→                        .build();
 71→                matchRepository.save(match);
 72→            }
 73→            maxSimilarity = Math.max(maxSimilarity, similarity);
 74→        }
 75→
 76→        List<StandardizedContentRecord> contentRecords = contentRepository.findByIsPublished(true);
 77→        for (StandardizedContentRecord content : contentRecords) {
 78→            if (content.getBodyText() == null) continue;
 79→            Set<Long> contentFp = FingerprintUtil.generateFingerprint(content.getBodyText(), ngramSize, windowSize);
 80→            double similarity = FingerprintUtil.computeSimilarity(sourceFingerprint, contentFp);
 81→
 82→            if (similarity >= similarityThreshold) {
 83→                PlagiarismMatch match = PlagiarismMatch.builder()
 84→                        .plagiarismCheck(check).matchedContent(content)
 85→                        .similarityScore(BigDecimal.valueOf(similarity))
 86→                        .matchedTextExcerpt(content.getBodyText().substring(0, Math.min(200, content.getBodyText().length())))
 87→                        .sourceTextExcerpt(submissionText.substring(0, Math.min(200, submissionText.length())))
 88→                        .build();
 89→                matchRepository.save(match);
 90→            }
 91→            maxSimilarity = Math.max(maxSimilarity, similarity);
 92→        }
 93→
 94→        check.setMaxSimilarityScore(BigDecimal.valueOf(maxSimilarity));
 95→        check.setIsFlagged(maxSimilarity >= similarityThreshold);
 96→        check.setStatus("COMPLETED");
 97→        check.setCheckedAt(LocalDateTime.now());
 98→        return checkRepository.save(check);
 99→    }
100→
101→    public PlagiarismCheck getCheck(Long id) {
102→        return checkRepository.findById(id)
103→                .orElseThrow(() -> new ResourceNotFoundException("Plagiarism check not found: " + id));
104→    }
105→
106→    public List<PlagiarismMatch> getMatches(Long checkId) {
107→        return matchRepository.findByPlagiarismCheckId(checkId);
108→    }
109→
110→    public List<PlagiarismCheck> getFlaggedChecks() {
111→        return checkRepository.findByIsFlagged(true);
112→    }
113→
114→    public List<PlagiarismCheck> getAllChecks() {
115→        return checkRepository.findAll();
116→    }
117→
118→    private String buildSubmissionText(Submission submission) {
119→        StringBuilder sb = new StringBuilder();
120→        for (SubmissionAnswer answer : submission.getAnswers()) {
121→            if (answer.getAnswerText() != null) sb.append(answer.getAnswerText()).append(" ");
122→        }
123→        return sb.toString().trim();
124→    }
125→}
