 99→        log.warn("Validation failed: {} field error(s)", ex.getBindingResult().getFieldErrors().size());
100→        Map<String, String> fieldErrors = ex.getBindingResult().getFieldErrors().stream()
101→                .collect(Collectors.toMap(
102→                        fe -> fe.getField(),
103→                        fe -> fe.getDefaultMessage() != null ? fe.getDefaultMessage() : "Invalid value",
104→                        (existing, replacement) -> existing
105→                ));
106→        return ResponseEntity.status(HttpStatus.BAD_REQUEST)
107→                .body(ApiResponse.<Map<String, String>>builder()
108→                        .success(false)
109→                        .error("Validation failed")
110→                        .data(fieldErrors)
111→                        .build());
