120→
121→    @ExceptionHandler(Exception.class)
122→    public ResponseEntity<ApiResponse<Void>> handleGenericException(Exception ex) {
123→        log.error("Unexpected error occurred: {}", ex.getClass().getSimpleName(), ex);
124→        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
125→                .body(ApiResponse.error("An unexpected error occurred. Please try again later."));
126→    }
127→}
