 53→              v-for="session in getSessionsForDay(day.index)"
 54→              :key="session.id"
 55→              :session="session"
 56→              :style="sessionStyle(session)"
 57→              class="timetable-editor__session-positioned"
 58→              @click="emit('selectSession', session)"
 59→              @dragstart="onDragStart(session, $event)"
 60→              @dragend="onDragEnd"
 61→            />
 62→          </div>
 63→        </div>
 64→      </div>
