 1→package com.scholarops.util;
 2→
 3→import javax.crypto.Cipher;
 4→import javax.crypto.spec.IvParameterSpec;
 5→import javax.crypto.spec.SecretKeySpec;
 6→import java.nio.charset.StandardCharsets;
 7→import java.security.SecureRandom;
 8→
 9→public final class AesEncryptionUtil {
10→
11→    private static final String ALGORITHM = "AES";
12→    private static final String TRANSFORMATION = "AES/CBC/PKCS5Padding";
13→    private static final int IV_LENGTH = 16;
14→
15→    private AesEncryptionUtil() {
16→        // Utility class
17→    }
18→
19→    public static EncryptedData encrypt(String plaintext, String key) {
20→        try {
21→            SecretKeySpec secretKey = buildKey(key);
22→            byte[] iv = generateIv();
23→            IvParameterSpec ivSpec = new IvParameterSpec(iv);
24→
25→            Cipher cipher = Cipher.getInstance(TRANSFORMATION);
26→            cipher.init(Cipher.ENCRYPT_MODE, secretKey, ivSpec);
27→            byte[] ciphertext = cipher.doFinal(plaintext.getBytes(StandardCharsets.UTF_8));
28→
29→            return new EncryptedData(ciphertext, iv);
30→        } catch (Exception e) {
31→            throw new IllegalStateException("Encryption failed", e);
32→        }
33→    }
34→
35→    public static String decrypt(byte[] ciphertext, byte[] iv, String key) {
36→        try {
37→            SecretKeySpec secretKey = buildKey(key);
38→            IvParameterSpec ivSpec = new IvParameterSpec(iv);
39→
40→            Cipher cipher = Cipher.getInstance(TRANSFORMATION);
41→            cipher.init(Cipher.DECRYPT_MODE, secretKey, ivSpec);
42→            byte[] plainBytes = cipher.doFinal(ciphertext);
43→
44→            return new String(plainBytes, StandardCharsets.UTF_8);
45→        } catch (Exception e) {
46→            throw new IllegalStateException("Decryption failed", e);
47→        }
48→    }
49→
50→    private static byte[] generateIv() {
51→        byte[] iv = new byte[IV_LENGTH];
52→        new SecureRandom().nextBytes(iv);
53→        return iv;
54→    }
55→
56→    private static SecretKeySpec buildKey(String key) {
57→        byte[] keyBytes = key.getBytes(StandardCharsets.UTF_8);
58→        if (keyBytes.length != 32) {
59→            byte[] padded = new byte[32];
60→            System.arraycopy(keyBytes, 0, padded, 0, Math.min(keyBytes.length, 32));
61→            keyBytes = padded;
62→        }
63→        return new SecretKeySpec(keyBytes, ALGORITHM);
64→    }
65→
66→    public static class EncryptedData {
67→        private final byte[] ciphertext;
68→        private final byte[] iv;
69→
70→        public EncryptedData(byte[] ciphertext, byte[] iv) {
71→            this.ciphertext = ciphertext;
72→            this.iv = iv;
73→        }
74→
75→        public byte[] getCiphertext() {
76→            return ciphertext;
77→        }
78→
79→        public byte[] getIv() {
80→            return iv;
81→        }
82→    }
83→}
