 27→
 28→    public SubmissionService(SubmissionRepository submissionRepository, SubmissionAnswerRepository answerRepository,
 29→            QuizPaperRepository quizPaperRepository, QuestionRepository questionRepository,
 30→            UserRepository userRepository, AutoGradingService autoGradingService,
 31→            PlagiarismService plagiarismService, AuditLogService auditLogService,
 32→            GradingStateRepository gradingStateRepository) {
 33→        this.submissionRepository = submissionRepository;
 34→        this.answerRepository = answerRepository;
 35→        this.quizPaperRepository = quizPaperRepository;
 36→        this.questionRepository = questionRepository;
 37→        this.userRepository = userRepository;
 38→        this.autoGradingService = autoGradingService;
 39→        this.plagiarismService = plagiarismService;
 40→        this.auditLogService = auditLogService;
 41→        this.gradingStateRepository = gradingStateRepository;
 42→    }
 43→
 44→    @Transactional
 45→    public Submission startSubmission(Long quizPaperId, Long studentId) {
 46→        QuizPaper quiz = quizPaperRepository.findById(quizPaperId)
 47→                .orElseThrow(() -> new ResourceNotFoundException("Quiz not found"));
 48→        if (!quiz.getIsPublished()) throw new ForbiddenException("Quiz is not published");
 49→
 50→        LocalDateTime now = LocalDateTime.now();
 51→        if (quiz.getReleaseStart() != null && now.isBefore(quiz.getReleaseStart()))
 52→            throw new ForbiddenException("Quiz is not yet available");
 53→        if (quiz.getReleaseEnd() != null && now.isAfter(quiz.getReleaseEnd()))
 54→            throw new ForbiddenException("Quiz release window has ended");
 55→
 56→        long attemptCount = submissionRepository.countByQuizPaperIdAndStudentId(quizPaperId, studentId);
 57→        if (attemptCount >= quiz.getMaxAttempts())
 58→            throw new ConflictException("Maximum attempts (" + quiz.getMaxAttempts() + ") reached");
 59→
 60→        User student = userRepository.findById(studentId).orElseThrow();
 61→        Submission submission = Submission.builder()
 62→                .quizPaper(quiz).student(student)
 63→                .attemptNumber((int) attemptCount + 1)
 64→                .status("IN_PROGRESS")
 65→                .timeRemainingSeconds(quiz.getTimeLimitMinutes() != null ? quiz.getTimeLimitMinutes() * 60 : null)
 66→                .maxScore(quiz.getTotalPoints())
 67→                .build();
 68→        submission = submissionRepository.save(submission);
 69→
 70→        auditLogService.log(studentId, AuditAction.SUBMISSION_START, "Submission", submission.getId(),
 71→                "Started quiz attempt " + submission.getAttemptNumber(), null, null);
 72→        return submission;
 73→    }
 74→
 75→    @Transactional
 76→    public void autosave(Long submissionId, AutosaveRequest request, Long studentId) {
 77→        Submission submission = getOwnSubmission(submissionId, studentId);
 78→        if (!"IN_PROGRESS".equals(submission.getStatus())) return;
 79→
 80→        if (request.getAnswers() != null) {
 81→            for (AutosaveRequest.AnswerEntry entry : request.getAnswers()) {
 82→                SubmissionAnswer answer = answerRepository
 83→                        .findBySubmissionIdAndQuestionId(submission.getId(), entry.getQuestionId())
 84→                        .orElseGet(() -> {
 85→                            Question q = questionRepository.findById(entry.getQuestionId()).orElseThrow();
 86→                            return SubmissionAnswer.builder().submission(submission).question(q).build();
 87→                        });
 88→                answer.setAnswerText(entry.getAnswerText());
 89→                answer.setSelectedOption(entry.getSelectedOption());
 90→                answerRepository.save(answer);
 91→            }
 92→        }
 93→        submission.setTimeRemainingSeconds(request.getTimeRemainingSeconds());
 94→        submission.setAutoSavedAt(LocalDateTime.now());
 95→        submissionRepository.save(submission);
 96→    }
 97→
 98→    @Transactional
 99→    public Submission submitSubmission(Long submissionId, Long studentId) {
100→        Submission submission = getOwnSubmission(submissionId, studentId);
101→        if (!"IN_PROGRESS".equals(submission.getStatus()))
102→            throw new ConflictException("Submission already submitted");
103→
104→        submission.setStatus("SUBMITTED");
105→        submission.setSubmittedAt(LocalDateTime.now());
106→
107→        String allAnswers = submission.getAnswers().stream()
108→                .map(a -> a.getAnswerText() != null ? a.getAnswerText() : "")
109→                .collect(Collectors.joining(" "));
110→        submission.setFingerprintHash(FingerprintUtil.hashText(allAnswers));
111→
112→        submission = submissionRepository.save(submission);
113→        autoGradingService.gradeObjectiveAnswers(submission);
114→        plagiarismService.checkSubmission(submission);
115→
116→        auditLogService.log(studentId, AuditAction.SUBMISSION_SUBMIT, "Submission", submissionId,
117→                "Submitted quiz", null, null);
118→        return submission;
119→    }
120→
121→    public Submission getSubmission(Long id, Long userId, boolean isInstructor, boolean isTeachingAssistant) {
122→        Submission submission = submissionRepository.findById(id)
123→                .orElseThrow(() -> new ResourceNotFoundException("Submission not found: " + id));
124→        if (submission.getStudent().getId().equals(userId)) {
125→            return submission;
126→        }
127→
128→        if (isInstructor) {
129→            Long quizOwnerId = submission.getQuizPaper().getCreatedBy().getId();
130→            if (quizOwnerId != null && quizOwnerId.equals(userId)) {
131→                return submission;
132→            }
133→        }
134→
135→        if (isTeachingAssistant && gradingStateRepository.existsBySubmissionIdAndAssignedToId(id, userId)) {
136→            return submission;
137→        }
138→
139→        if (!isInstructor && !isTeachingAssistant) {
140→            throw new ForbiddenException("Not authorized to access this submission");
141→        }
142→        throw new ForbiddenException("Not authorized to access this submission");
143→    }
144→
145→    public Map<String, Object> getFeedback(Long submissionId, Long studentId) {
146→        Submission submission = getOwnSubmission(submissionId, studentId);
147→        Map<String, Object> feedback = new HashMap<>();
148→        feedback.put("submissionId", submissionId);
149→        feedback.put("status", submission.getStatus());
150→        feedback.put("totalScore", submission.getTotalScore());
151→        feedback.put("maxScore", submission.getMaxScore());
152→        feedback.put("answers", submission.getAnswers());
153→        return feedback;
154→    }
155→
156→    private Submission getOwnSubmission(Long submissionId, Long studentId) {
157→        Submission submission = submissionRepository.findById(submissionId)
158→                .orElseThrow(() -> new ResourceNotFoundException("Submission not found"));
159→        if (!submission.getStudent().getId().equals(studentId))
160→            throw new ForbiddenException("Not authorized to access this submission");
161→        return submission;
162→    }
163→}
