 3→import com.scholarops.util.AesEncryptionUtil;
 4→import org.springframework.beans.factory.annotation.Qualifier;
 5→import org.springframework.stereotype.Service;
 6→
 7→@Service
 8→public class EncryptionService {
 9→
10→    private final String aesEncryptionKey;
11→
12→    public EncryptionService(@Qualifier("aesEncryptionKey") String aesEncryptionKey) {
13→        this.aesEncryptionKey = aesEncryptionKey;
14→    }
15→
16→    /**
17→     * Encrypts plaintext using AES-256-CBC with the configured key.
18→     *
19→     * @param plaintext the text to encrypt
20→     * @return the encrypted data containing ciphertext and IV
21→     */
22→    public AesEncryptionUtil.EncryptedData encrypt(String plaintext) {
23→        if (plaintext == null || plaintext.isEmpty()) {
24→            throw new IllegalArgumentException("Plaintext must not be null or empty");
25→        }
26→        return AesEncryptionUtil.encrypt(plaintext, aesEncryptionKey);
27→    }
28→
29→    /**
30→     * Decrypts ciphertext using AES-256-CBC with the configured key.
31→     *
32→     * @param ciphertext the encrypted bytes
33→     * @param iv         the initialization vector used during encryption
34→     * @return the decrypted plaintext string
35→     */
36→    public String decrypt(byte[] ciphertext, byte[] iv) {
37→        if (ciphertext == null || ciphertext.length == 0) {
38→            throw new IllegalArgumentException("Ciphertext must not be null or empty");
39→        }
40→        if (iv == null || iv.length == 0) {
41→            throw new IllegalArgumentException("IV must not be null or empty");
42→        }
43→        return AesEncryptionUtil.decrypt(ciphertext, iv, aesEncryptionKey);
44→    }
45→}
