 26→<script setup lang="ts">
 27→import { computed, onMounted, ref } from 'vue'
 28→import RuleVersionEditor from '@/components/curator/RuleVersionEditor.vue'
 29→import { createRule, getRules, getSources, revertRule } from '@/api/crawl'
 30→import type { CrawlRuleVersion, CrawlSource } from '@/types/crawl'
 31→
 32→const sources = ref<CrawlSource[]>([])
 33→const selectedSourceId = ref(0)
 34→const versions = ref<CrawlRuleVersion[]>([])
 35→const saving = ref(false)
 36→
 37→const currentVersion = computed(() => versions.value.find(v => v.isActive) ?? versions.value[0] ?? null)
 38→
 39→async function loadSources() {
 40→  sources.value = await getSources()
 41→}
 42→
 43→async function loadRules() {
 44→  if (!selectedSourceId.value) {
 45→    versions.value = []
 46→    return
 47→  }
 48→  versions.value = await getRules(selectedSourceId.value)
 49→}
 50→
 51→async function onSave(data: { extractionMethod: string; ruleDefinition: string; fieldMappings: string; notes: string }) {
 52→  if (!selectedSourceId.value) return
 53→  saving.value = true
 54→  try {
 55→    await createRule(selectedSourceId.value, {
 56→      extractionMethod: data.extractionMethod,
 57→      ruleDefinition: safeJsonParse(data.ruleDefinition),
 58→      fieldMappings: safeJsonParse(data.fieldMappings),
 59→      notes: data.notes,
 60→    })
 61→    await loadRules()
 62→  } finally {
 63→    saving.value = false
 64→  }
 65→}
 66→
 67→async function onRevert(targetVersionId: number) {
 68→  const ruleId = currentVersion.value?.id ?? targetVersionId
 69→  await revertRule(ruleId, targetVersionId)
 70→  await loadRules()
 71→}
 72→
 73→function onCancel() {
 74→  // No local draft cache yet; keeping event wired for UX contract completeness.
 75→}
 76→
 77→function safeJsonParse(value: string): Record<string, unknown> {
 78→  if (!value || !value.trim()) return {}
 79→  try {
 80→    return JSON.parse(value)
 81→  } catch {
 82→    return {}
 83→  }
 84→}
 85→
 86→onMounted(async () => {
 87→  await loadSources()
 88→})
