 16→@Service
 17→public class SubmissionService {
 18→    private final SubmissionRepository submissionRepository;
 19→    private final SubmissionAnswerRepository answerRepository;
 20→    private final QuizPaperRepository quizPaperRepository;
 21→    private final QuestionRepository questionRepository;
 22→    private final UserRepository userRepository;
 23→    private final AutoGradingService autoGradingService;
 24→    private final PlagiarismService plagiarismService;
 25→    private final AuditLogService auditLogService;
 26→    private final GradingStateRepository gradingStateRepository;
