  1→<template>
  2→  <div class="assessment-view">
  3→    <div class="assessment-view__header">
  4→      <h2 class="assessment-view__title">{{ quizTitle }}</h2>
  5→      <div class="assessment-view__header-right">
  6→        <CountdownTimer
  7→          :timeRemainingSeconds="timeRemaining"
  8→          @expired="handleTimeExpired"
  9→          @tick="onTimerTick"
 10→        />
 11→        <span class="assessment-view__autosave" :class="{ 'assessment-view__autosave--saving': isSaving }">
 12→          {{ isSaving ? 'Saving...' : lastSaved ? `Saved at ${lastSaved}` : '' }}
 13→        </span>
 14→      </div>
 15→    </div>
 16→
 17→    <div class="assessment-view__progress">
 18→      <div class="assessment-view__progress-bar">
 19→        <div
 20→          class="assessment-view__progress-fill"
 21→          :style="{ width: `${progressPercent}%` }"
 22→        ></div>
 23→      </div>
 24→      <span class="assessment-view__progress-text">{{ answeredCount }} / {{ questions.length }} answered</span>
 25→    </div>
 26→
 27→    <div class="assessment-view__question-area">
 28→      <div v-if="currentQuestion" class="assessment-view__question">
 29→        <div class="assessment-view__question-header">
 30→          <span class="assessment-view__question-number">Question {{ currentIndex + 1 }} of {{ questions.length }}</span>
 31→          <span class="assessment-view__question-points">{{ currentQuestion.points }} pts</span>
 32→        </div>
 33→
 34→        <p class="assessment-view__question-text">{{ currentQuestion.questionText }}</p>
 35→
 36→        <div v-if="currentQuestion.questionType === 'MULTIPLE_CHOICE'" class="assessment-view__options">
 37→          <label
 38→            v-for="(option, idx) in parsedOptions"
 39→            :key="idx"
 40→            class="assessment-view__option"
 41→            :class="{
 42→              'assessment-view__option--selected': answers[currentQuestion.id]?.selectedOption === option,
 43→              'assessment-view__option--correct': showFeedback && option === currentQuestion.correctAnswer,
 44→              'assessment-view__option--incorrect': showFeedback && answers[currentQuestion.id]?.selectedOption === option && option !== currentQuestion.correctAnswer,
 45→            }"
 46→          >
 47→            <input
 48→              type="radio"
 49→              :name="`q-${currentQuestion.id}`"
 50→              :value="option"
 51→              :checked="answers[currentQuestion.id]?.selectedOption === option"
 52→              @change="selectOption(currentQuestion.id, option)"
 53→              class="assessment-view__radio"
 54→              :disabled="showFeedback"
 55→            />
 56→            <span class="assessment-view__option-label">{{ String.fromCharCode(65 + idx) }}.</span>
 57→            <span class="assessment-view__option-text">{{ option }}</span>
 58→          </label>
 59→        </div>
 60→
 61→        <div v-else class="assessment-view__text-answer">
 62→          <textarea
 63→            :value="answers[currentQuestion.id]?.answerText || ''"
 64→            @input="setAnswerText(currentQuestion.id, ($event.target as HTMLTextAreaElement).value)"
 65→            class="assessment-view__textarea"
 66→            rows="6"
 67→            placeholder="Type your answer here..."
 68→            :disabled="showFeedback"
 69→          ></textarea>
 70→        </div>
 71→
 72→        <div v-if="showFeedback && feedback" class="assessment-view__feedback">
 73→          <p class="assessment-view__feedback-result" :class="feedback.isCorrect ? 'assessment-view__feedback-result--correct' : 'assessment-view__feedback-result--incorrect'">
 74→            {{ feedback.isCorrect ? 'Correct!' : 'Incorrect' }}
 75→          </p>
 76→          <p v-if="currentQuestion.explanation" class="assessment-view__feedback-explanation">
 77→            {{ currentQuestion.explanation }}
 78→          </p>
 79→        </div>
 80→      </div>
 81→    </div>
 82→
 83→    <div class="assessment-view__navigation">
 84→      <button type="button" class="assessment-view__nav-btn" @click="prevQuestion" :disabled="currentIndex === 0">Previous</button>
 85→      <div class="assessment-view__question-dots">
 86→        <button
 87→          v-for="(q, idx) in questions"
 88→          :key="q.id"
 89→          type="button"
 90→          class="assessment-view__dot"
 91→          :class="{
 92→            'assessment-view__dot--active': idx === currentIndex,
 93→            'assessment-view__dot--answered': !!answers[q.id],
 94→          }"
 95→          @click="currentIndex = idx"
 96→        >
 97→          {{ idx + 1 }}
 98→        </button>
 99→      </div>
100→      <button
101→        v-if="currentIndex < questions.length - 1"
102→        type="button"
103→        class="assessment-view__nav-btn"
104→        @click="nextQuestion"
105→      >
106→        Next
107→      </button>
108→      <button
109→        v-else
110→        type="button"
111→        class="assessment-view__submit-btn"
112→        @click="emit('submit')"
113→      >
114→        Submit Assessment
115→      </button>
116→    </div>
117→  </div>
