 50→import { ref, computed, onMounted } from 'vue'
 51→import { useRoute } from 'vue-router'
 52→import QuizScheduleForm from '@/components/instructor/QuizScheduleForm.vue'
 53→import { getQuiz, publishQuiz as apiPublish, scheduleQuiz } from '@/api/quiz'
 54→import type { QuizPaper } from '@/types/quiz'
 55→
 56→const route = useRoute()
 57→const quiz = ref<QuizPaper | null>(null)
 58→const loading = ref(false)
 59→const showSchedule = ref(false)
 60→const scheduleSaving = ref(false)
 61→
 62→const scheduleInitial = computed(() => {
 63→  if (!quiz.value) return null
 64→  return {
 65→    releaseStart: quiz.value.releaseStart,
 66→    releaseEnd: quiz.value.releaseEnd,
 67→    timeLimitMinutes: quiz.value.timeLimitMinutes,
 68→    maxAttempts: quiz.value.maxAttempts,
 69→  }
 70→})
 71→
 72→async function loadQuiz() {
 73→  loading.value = true
 74→  try {
 75→    quiz.value = await getQuiz(Number(route.params.id))
 76→  } catch (e) {
 77→    console.error(e)
 78→  } finally {
 79→    loading.value = false
 80→  }
 81→}
 82→
 83→async function onPublish() {
 84→  if (!quiz.value) return
 85→  try {
 86→    await apiPublish(quiz.value.id)
 87→    await loadQuiz()
 88→  } catch (e) {
 89→    alert('Failed to publish')
 90→  }
 91→}
 92→
 93→async function onScheduleSubmit(data: { releaseStart: string; releaseEnd: string; timeLimitMinutes: number; maxAttempts: number }) {
 94→  if (!quiz.value) return
 95→  scheduleSaving.value = true
 96→  try {
 97→    await scheduleQuiz(quiz.value.id, data.releaseStart, data.releaseEnd)
 98→    showSchedule.value = false
 99→    await loadQuiz()
100→  } catch (e) {
101→    console.error(e)
102→  } finally {
103→    scheduleSaving.value = false
104→  }
105→}
106→
107→onMounted(loadQuiz)
