 85→<script setup lang="ts">
 86→import { reactive, computed } from 'vue'
 87→import type { QuizRule } from '@/types/quiz'
 88→
 89→const props = defineProps<{
 90→  assembling: boolean
 91→}>()
 92→
 93→const emit = defineEmits<{
 94→  preview: [rules: QuizRule[]]
 95→  assemble: [data: { totalQuestions: number; rules: QuizRule[] }]
 96→}>()
 97→
 98→const form = reactive({
 99→  totalQuestions: 20,
100→  constraints: [
101→    { difficultyLevel: 1, minCount: 0, maxCount: 0 },
102→    { difficultyLevel: 2, minCount: 2, maxCount: 5 },
103→    { difficultyLevel: 3, minCount: 6, maxCount: 10 },
104→    { difficultyLevel: 4, minCount: 3, maxCount: 6 },
105→    { difficultyLevel: 5, minCount: 2, maxCount: 4 },
106→  ],
107→})
108→
109→const totalMin = computed(() => form.constraints.reduce((s, c) => s + (c.minCount || 0), 0))
110→const totalMax = computed(() => form.constraints.reduce((s, c) => s + (c.maxCount || 0), 0))
111→
112→const validationError = computed(() => {
113→  if (totalMin.value > form.totalQuestions) {
114→    return `Minimum constraints (${totalMin.value}) exceed total questions (${form.totalQuestions}).`
115→  }
116→  if (totalMax.value < form.totalQuestions) {
117→    return `Maximum constraints (${totalMax.value}) are less than total questions (${form.totalQuestions}).`
118→  }
119→  return ''
120→})
121→
122→function buildRules(): QuizRule[] {
123→  return form.constraints
124→    .filter(c => c.minCount > 0 || c.maxCount > 0)
125→    .map(c => ({
126→      ruleType: 'DIFFICULTY',
127→      difficultyLevel: c.difficultyLevel,
128→      minCount: c.minCount,
129→      maxCount: c.maxCount,
130→    }))
131→}
132→
133→function handleAssemble() {
134→  if (validationError.value) return
135→  emit('assemble', { totalQuestions: form.totalQuestions, rules: buildRules() })
136→}
137→</script>
