23→    public ScheduleService(ScheduleRepository scheduleRepository, LockedPeriodRepository lockedPeriodRepository,
24→            ScheduleChangeJournalRepository journalRepository, UserRepository userRepository,
25→            AuditLogService auditLogService, TimetableService timetableService) {
26→        this.scheduleRepository = scheduleRepository;
27→        this.lockedPeriodRepository = lockedPeriodRepository;
