34→    @Transactional
35→    public Schedule createSchedule(ScheduleRequest request, Long userId) {
36→        timetableService.checkLockedPeriodConflict(userId, request.getStartTime(), request.getEndTime());
37→        User user = userRepository.findById(userId).orElseThrow();
38→        Schedule schedule = Schedule.builder()
39→                .user(user).title(request.getTitle()).description(request.getDescription())
40→                .startTime(request.getStartTime()).endTime(request.getEndTime())
41→                .dayOfWeek(request.getDayOfWeek() != null ? request.getDayOfWeek().getValue() : null)
42→                .isRecurring(request.getIsRecurring() != null && request.getIsRecurring())
43→                .color(request.getColor()).contentRecordId(request.getContentRecordId())
44→                .quizPaperId(request.getQuizPaperId()).build();
45→        schedule = scheduleRepository.save(schedule);
46→        timetableService.recordJournal(userId, schedule.getId(), "CREATE", null, schedule);
47→        auditLogService.log(userId, AuditAction.SCHEDULE_CREATE, "Schedule", schedule.getId(),
48→                "Created schedule: " + schedule.getTitle(), null, null);
49→        return schedule;
50→    }
51→
52→    @Transactional
53→    public Schedule updateSchedule(Long id, ScheduleRequest request, Long userId) {
54→        Schedule schedule = getOwnSchedule(id, userId);
55→        timetableService.checkLockedPeriodConflict(userId, request.getStartTime(), request.getEndTime());
56→        Schedule previous = cloneSchedule(schedule);
57→        schedule.setTitle(request.getTitle());
58→        schedule.setDescription(request.getDescription());
59→        schedule.setStartTime(request.getStartTime());
60→        schedule.setEndTime(request.getEndTime());
61→        schedule.setDayOfWeek(request.getDayOfWeek() != null ? request.getDayOfWeek().getValue() : null);
62→        schedule.setColor(request.getColor());
63→        schedule = scheduleRepository.save(schedule);
64→        timetableService.recordJournal(userId, schedule.getId(), "UPDATE", previous, schedule);
65→        auditLogService.log(userId, AuditAction.SCHEDULE_UPDATE, "Schedule", id, "Updated schedule", null, null);
66→        return schedule;
67→    }
68→
69→    @Transactional
70→    public void deleteSchedule(Long id, Long userId) {
71→        Schedule schedule = getOwnSchedule(id, userId);
72→        timetableService.recordJournal(userId, schedule.getId(), "DELETE", schedule, null);
73→        scheduleRepository.delete(schedule);
74→        auditLogService.log(userId, AuditAction.SCHEDULE_DELETE, "Schedule", id, "Deleted schedule", null, null);
75→    }
76→
77→    public List<Schedule> getSchedules(Long userId, LocalDateTime start, LocalDateTime end) {
78→        if (start != null && end != null) {
79→            return scheduleRepository.findByUserIdAndStartTimeBetween(userId, start, end);
