  1→package com.scholarops.service;
  2→
  3→import com.scholarops.exception.*;
  4→import com.scholarops.model.entity.*;
  5→import com.scholarops.model.enums.AuditAction;
  6→import com.scholarops.repository.*;
  7→import com.fasterxml.jackson.databind.ObjectMapper;
  8→import org.springframework.stereotype.Service;
  9→import org.springframework.transaction.annotation.Transactional;
 10→
 11→import java.time.LocalDateTime;
 12→import java.util.*;
 13→
 14→@Service
 15→public class TimetableService {
 16→    private final ScheduleRepository scheduleRepository;
 17→    private final ScheduleChangeJournalRepository journalRepository;
 18→    private final LockedPeriodRepository lockedPeriodRepository;
 19→    private final UserRepository userRepository;
 20→    private final AuditLogService auditLogService;
 21→    private final ObjectMapper objectMapper;
 22→
 23→    public TimetableService(ScheduleRepository scheduleRepository, ScheduleChangeJournalRepository journalRepository,
 24→            LockedPeriodRepository lockedPeriodRepository, UserRepository userRepository,
 25→            AuditLogService auditLogService, ObjectMapper objectMapper) {
 26→        this.scheduleRepository = scheduleRepository;
 27→        this.journalRepository = journalRepository;
 28→        this.lockedPeriodRepository = lockedPeriodRepository;
 29→        this.userRepository = userRepository;
 30→        this.auditLogService = auditLogService;
 31→        this.objectMapper = objectMapper;
 32→    }
 33→
 34→    @Transactional
 35→    public Schedule moveSchedule(Long scheduleId, LocalDateTime newStart, LocalDateTime newEnd, Long userId) {
 36→        Schedule schedule = getOwnSchedule(scheduleId, userId);
 37→        checkLockedPeriodConflict(userId, newStart, newEnd);
 38→        Schedule previous = snapshot(schedule);
 39→        schedule.setStartTime(newStart);
 40→        schedule.setEndTime(newEnd);
 41→        schedule = scheduleRepository.save(schedule);
 42→        recordJournal(userId, scheduleId, "MOVE", previous, schedule);
 43→        auditLogService.log(userId, AuditAction.SCHEDULE_MOVE, "Schedule", scheduleId, "Moved schedule", null, null);
 44→        return schedule;
 45→    }
 46→
 47→    @Transactional
 48→    public Schedule mergeSchedules(List<Long> scheduleIds, Long userId) {
 49→        if (scheduleIds == null || scheduleIds.size() < 2)
 50→            throw new IllegalArgumentException("At least 2 schedules required for merge");
 51→        List<Schedule> schedules = new ArrayList<>();
 52→        for (Long id : scheduleIds) {
 53→            schedules.add(getOwnSchedule(id, userId));
 54→        }
 55→        schedules.sort(Comparator.comparing(Schedule::getStartTime));
 56→        LocalDateTime mergedStart = schedules.get(0).getStartTime();
 57→        LocalDateTime mergedEnd = schedules.get(schedules.size() - 1).getEndTime();
 58→        checkLockedPeriodConflict(userId, mergedStart, mergedEnd);
 59→
 60→        Schedule merged = Schedule.builder()
 61→                .user(userRepository.findById(userId).orElseThrow())
 62→                .title(schedules.get(0).getTitle() + " (merged)")
 63→                .startTime(mergedStart).endTime(mergedEnd)
 64→                .color(schedules.get(0).getColor()).build();
 65→        merged = scheduleRepository.save(merged);
 66→
 67→        for (Schedule s : schedules) {
 68→            scheduleRepository.delete(s);
 69→        }
 70→        recordJournal(userId, merged.getId(), "MERGE", null, merged);
 71→        auditLogService.log(userId, AuditAction.SCHEDULE_MERGE, "Schedule", merged.getId(), "Merged schedules", null, null);
 72→        return merged;
 73→    }
 74→
 75→    @Transactional
 76→    public List<Schedule> splitSchedule(Long scheduleId, LocalDateTime splitTime, Long userId) {
 77→        Schedule schedule = getOwnSchedule(scheduleId, userId);
 78→        if (!splitTime.isAfter(schedule.getStartTime()) || !splitTime.isBefore(schedule.getEndTime()))
 79→            throw new IllegalArgumentException("Split time must be within the schedule's time range");
 80→
 81→        User user = userRepository.findById(userId).orElseThrow();
 82→        Schedule first = Schedule.builder().user(user).title(schedule.getTitle() + " (1)")
 83→                .startTime(schedule.getStartTime()).endTime(splitTime).color(schedule.getColor()).build();
 84→        Schedule second = Schedule.builder().user(user).title(schedule.getTitle() + " (2)")
 85→                .startTime(splitTime).endTime(schedule.getEndTime()).color(schedule.getColor()).build();
 86→        first = scheduleRepository.save(first);
 87→        second = scheduleRepository.save(second);
 88→        scheduleRepository.delete(schedule);
 89→        recordJournal(userId, scheduleId, "SPLIT", schedule, null);
 90→        auditLogService.log(userId, AuditAction.SCHEDULE_SPLIT, "Schedule", scheduleId, "Split schedule", null, null);
 91→        return List.of(first, second);
 92→    }
 93→
 94→    @Transactional
 95→    public Schedule undo(Long userId) {
 96→        List<ScheduleChangeJournal> entries = journalRepository.findByUserIdAndIsUndone(userId, false);
 97→        if (entries.isEmpty()) throw new ResourceNotFoundException("Nothing to undo");
 98→        ScheduleChangeJournal last = entries.get(0);
 99→        last.setIsUndone(true);
100→        journalRepository.save(last);
101→        // Restore previous state if available
102→        if (last.getPreviousState() != null && last.getSchedule() != null) {
103→            try {
104→                Schedule restored = objectMapper.readValue(last.getPreviousState(), Schedule.class);
105→                return scheduleRepository.save(restored);
106→            } catch (Exception e) { /* fall through */ }
107→        }
108→        return null;
109→    }
110→
111→    @Transactional
112→    public Schedule redo(Long userId) {
113→        List<ScheduleChangeJournal> undoneEntries = journalRepository.findByUserIdAndIsUndone(userId, true);
114→        if (undoneEntries.isEmpty()) throw new ResourceNotFoundException("Nothing to redo");
115→        ScheduleChangeJournal last = undoneEntries.get(undoneEntries.size() - 1);
116→        last.setIsUndone(false);
117→        journalRepository.save(last);
118→        if (last.getNewState() != null && last.getSchedule() != null) {
119→            try {
120→                Schedule restored = objectMapper.readValue(last.getNewState(), Schedule.class);
121→                return scheduleRepository.save(restored);
122→            } catch (Exception e) { /* fall through */ }
123→        }
124→        return null;
125→    }
126→
127→    public List<ScheduleChangeJournal> getChangeJournal(Long userId) {
128→        return journalRepository.findByUserIdOrderBySequenceNumberDesc(userId);
129→    }
130→
131→    public void checkLockedPeriodConflict(Long userId, LocalDateTime start, LocalDateTime end) {
132→        List<LockedPeriod> conflicts = lockedPeriodRepository.findConflicting(userId, start, end);
133→        if (!conflicts.isEmpty()) {
134→            LockedPeriod conflict = conflicts.get(0);
135→            throw new LockedPeriodConflictException(
136→                    "Schedule conflicts with locked period: " + conflict.getTitle() +
137→                    " (" + conflict.getStartTime() + " - " + conflict.getEndTime() + ")",
138→                    conflict.getId(), conflict.getTitle(), conflict.getStartTime(), conflict.getEndTime());
139→        }
140→    }
141→
142→    public LockedPeriod createLockedPeriod(Long userId, String title, LocalDateTime start, LocalDateTime end, String reason) {
143→        User user = userRepository.findById(userId).orElseThrow();
144→        LockedPeriod period = LockedPeriod.builder().user(user).title(title)
145→                .startTime(start).endTime(end).reason(reason).build();
146→        return lockedPeriodRepository.save(period);
147→    }
148→
149→    public void deleteLockedPeriod(Long id, Long userId) {
150→        LockedPeriod period = lockedPeriodRepository.findById(id)
151→                .orElseThrow(() -> new ResourceNotFoundException("Locked period not found"));
152→        if (!period.getUser().getId().equals(userId))
153→            throw new ForbiddenException("Not authorized");
154→        lockedPeriodRepository.delete(period);
155→    }
156→
157→    public List<LockedPeriod> getLockedPeriods(Long userId) {
158→        return lockedPeriodRepository.findByUserId(userId);
159→    }
160→
161→    void recordJournal(Long userId, Long scheduleId, String changeType, Schedule previous, Schedule current) {
162→        int nextSeq = journalRepository.findTopByUserIdOrderBySequenceNumberDesc(userId)
163→                .map(j -> j.getSequenceNumber() + 1).orElse(1);
164→        try {
165→            ScheduleChangeJournal entry = ScheduleChangeJournal.builder()
166→                    .user(userRepository.findById(userId).orElseThrow())
167→                    .schedule(scheduleId != null ? scheduleRepository.findById(scheduleId).orElse(null) : null)
168→                    .changeType(changeType)
169→                    .previousState(previous != null ? objectMapper.writeValueAsString(previous) : null)
170→                    .newState(current != null ? objectMapper.writeValueAsString(current) : null)
171→                    .sequenceNumber(nextSeq).build();
172→            journalRepository.save(entry);
173→        } catch (Exception e) { /* log and continue */ }
174→    }
175→
176→    private Schedule getOwnSchedule(Long id, Long userId) {
177→        Schedule schedule = scheduleRepository.findById(id)
178→                .orElseThrow(() -> new ResourceNotFoundException("Schedule not found: " + id));
179→        if (!schedule.getUser().getId().equals(userId))
180→            throw new ForbiddenException("Not authorized");
181→        return schedule;
182→    }
183→
184→    private Schedule snapshot(Schedule s) {
185→        return Schedule.builder().id(s.getId()).title(s.getTitle()).startTime(s.getStartTime())
186→                .endTime(s.getEndTime()).dayOfWeek(s.getDayOfWeek()).color(s.getColor()).build();
187→    }
188→}
