 3→import com.scholarops.model.entity.*;
 4→import com.scholarops.repository.*;
 5→import org.springframework.stereotype.Service;
 6→import org.springframework.transaction.annotation.Transactional;
 7→
 8→import java.math.BigDecimal;
 9→import java.time.LocalDateTime;
10→
11→@Service
12→public class AutoGradingService {
13→    private final SubmissionAnswerRepository answerRepository;
14→    private final WrongAnswerHistoryRepository wrongAnswerRepository;
15→    private final GradingWorkflowService gradingWorkflowService;
16→
17→    public AutoGradingService(SubmissionAnswerRepository answerRepository,
18→            WrongAnswerHistoryRepository wrongAnswerRepository,
19→            GradingWorkflowService gradingWorkflowService) {
20→        this.answerRepository = answerRepository;
21→        this.wrongAnswerRepository = wrongAnswerRepository;
22→        this.gradingWorkflowService = gradingWorkflowService;
23→    }
24→
25→    @Transactional
26→    public void gradeObjectiveAnswers(Submission submission) {
27→        BigDecimal totalScore = BigDecimal.ZERO;
28→        for (SubmissionAnswer answer : submission.getAnswers()) {
29→            Question question = answer.getQuestion();
30→            if (question.isObjective()) {
31→                boolean correct = checkAnswer(answer, question);
32→                answer.setIsCorrect(correct);
33→                answer.setAutoGraded(true);
34→                answer.setGradedAt(LocalDateTime.now());
35→                answer.setScore(correct ? question.getPoints() : BigDecimal.ZERO);
36→                answerRepository.save(answer);
37→
38→                if (correct) {
39→                    totalScore = totalScore.add(question.getPoints());
40→                } else {
41→                    WrongAnswerHistory wrong = WrongAnswerHistory.builder()
42→                            .student(submission.getStudent())
43→                            .question(question)
44→                            .submission(submission)
45→                            .studentAnswer(answer.getAnswerText() != null ? answer.getAnswerText() : answer.getSelectedOption())
46→                            .correctAnswer(question.getCorrectAnswer())
47→                            .explanation(question.getExplanation())
48→                            .build();
49→                    wrongAnswerRepository.save(wrong);
50→                }
51→            } else {
52→                gradingWorkflowService.routeToQueue(answer);
53→            }
54→        }
55→
56→        submission.setTotalScore(totalScore);
57→        submission.setStatus("AUTO_GRADED");
58→    }
59→
60→    private boolean checkAnswer(SubmissionAnswer answer, Question question) {
61→        String correctAnswer = question.getCorrectAnswer();
62→        if (correctAnswer == null) return false;
63→        String studentAnswer = answer.getSelectedOption() != null ? answer.getSelectedOption() : answer.getAnswerText();
64→        if (studentAnswer == null) return false;
65→        return correctAnswer.trim().equalsIgnoreCase(studentAnswer.trim());
66→    }
67→}
