 16→
 17→@Service
 18→public class CatalogService {
 19→    private final StandardizedContentRecordRepository contentRepository;
 20→    private final EntityManager entityManager;
 21→
 22→    public CatalogService(StandardizedContentRecordRepository contentRepository, EntityManager entityManager) {
 23→        this.contentRepository = contentRepository;
 24→        this.entityManager = entityManager;
 25→    }
 26→
 27→    public Page<StandardizedContentRecord> search(CatalogSearchRequest request) {
 28→        CriteriaBuilder cb = entityManager.getCriteriaBuilder();
 29→        CriteriaQuery<StandardizedContentRecord> cq = cb.createQuery(StandardizedContentRecord.class);
 30→        Root<StandardizedContentRecord> root = cq.from(StandardizedContentRecord.class);
 31→
 32→        List<Predicate> predicates = new ArrayList<>();
 33→        predicates.add(cb.isTrue(root.get("isPublished")));
 34→
 35→        if (request.getKeyword() != null && !request.getKeyword().isBlank()) {
 36→            String kw = "%" + request.getKeyword().toLowerCase() + "%";
 37→            predicates.add(cb.or(
 38→                cb.like(cb.lower(root.get("title")), kw),
 39→                cb.like(cb.lower(root.get("description")), kw)
 40→            ));
 41→        }
 42→        if (request.getContentType() != null) {
 43→            predicates.add(cb.equal(root.get("contentType"), request.getContentType()));
 44→        }
 45→        if (request.getMinPrice() != null) {
 46→            predicates.add(cb.greaterThanOrEqualTo(root.get("price"), request.getMinPrice()));
 47→        }
 48→        if (request.getMaxPrice() != null) {
 49→            predicates.add(cb.lessThanOrEqualTo(root.get("price"), request.getMaxPrice()));
 50→        }
 51→        if (request.getAvailabilityStart() != null) {
 52→            predicates.add(cb.greaterThanOrEqualTo(root.get("availabilityStart"), request.getAvailabilityStart()));
 53→        }
 54→        if (request.getAvailabilityEnd() != null) {
 55→            predicates.add(cb.lessThanOrEqualTo(root.get("availabilityEnd"), request.getAvailabilityEnd()));
 56→        }
 57→
 58→        cq.where(predicates.toArray(new Predicate[0]));
 59→
 60→        if ("popularity".equalsIgnoreCase(request.getSortBy())) {
 61→            cq.orderBy("asc".equalsIgnoreCase(request.getSortDirection()) ?
 62→                    cb.asc(root.get("popularityScore")) : cb.desc(root.get("popularityScore")));
 63→        } else {
 64→            cq.orderBy("asc".equalsIgnoreCase(request.getSortDirection()) ?
 65→                    cb.asc(root.get("createdAt")) : cb.desc(root.get("createdAt")));
 66→        }
 67→
 68→        int page = request.getPage() != null ? request.getPage() : 0;
 69→        int size = request.getSize() != null ? request.getSize() : 20;
 70→
 71→        TypedQuery<StandardizedContentRecord> query = entityManager.createQuery(cq);
 72→        query.setFirstResult(page * size);
 73→        query.setMaxResults(size);
 74→        List<StandardizedContentRecord> results = query.getResultList();
 75→
 76→        CriteriaQuery<Long> countQuery = cb.createQuery(Long.class);
 77→        Root<StandardizedContentRecord> countRoot = countQuery.from(StandardizedContentRecord.class);
 78→        countQuery.select(cb.count(countRoot));
 79→        List<Predicate> countPredicates = new ArrayList<>();
 80→        countPredicates.add(cb.isTrue(countRoot.get("isPublished")));
 81→        if (request.getKeyword() != null && !request.getKeyword().isBlank()) {
 82→            String kw = "%" + request.getKeyword().toLowerCase() + "%";
 83→            countPredicates.add(cb.or(
 84→                cb.like(cb.lower(countRoot.get("title")), kw),
 85→                cb.like(cb.lower(countRoot.get("description")), kw)
 86→            ));
 87→        }
 88→        countQuery.where(countPredicates.toArray(new Predicate[0]));
 89→        Long total = entityManager.createQuery(countQuery).getSingleResult();
 90→
 91→        return new PageImpl<>(results, PageRequest.of(page, size), total);
 92→    }
