 89→        state.setScore(totalAwarded);
 90→        state.setStatus("GRADED");
 91→        state.setGradedAt(LocalDateTime.now());
 92→
 93→        SubmissionAnswer answer = state.getSubmissionAnswer();
 94→        answer.setScore(totalAwarded);
 95→        answer.setGradedAt(LocalDateTime.now());
