 10→import com.scholarops.repository.UserRepository;
 11→import com.scholarops.security.JwtTokenProvider;
 12→import com.scholarops.security.UserDetailsImpl;
 13→import com.scholarops.security.UserDetailsServiceImpl;
 14→import org.slf4j.Logger;
 15→import org.slf4j.LoggerFactory;
 16→import org.springframework.security.authentication.AuthenticationManager;
 17→import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
 18→import org.springframework.security.core.Authentication;
 19→import org.springframework.security.core.AuthenticationException;
 20→import org.springframework.security.core.GrantedAuthority;
 21→import org.springframework.security.crypto.password.PasswordEncoder;
 22→import org.springframework.stereotype.Service;
 23→import org.springframework.transaction.annotation.Transactional;
 24→
 25→import java.time.LocalDateTime;
 26→import java.util.List;
 27→import java.util.stream.Collectors;
 28→
 29→@Service
 30→public class AuthService {
 31→
 32→    private static final Logger logger = LoggerFactory.getLogger(AuthService.class);
 33→
 34→    private final AuthenticationManager authenticationManager;
 35→    private final JwtTokenProvider jwtTokenProvider;
 36→    private final UserDetailsServiceImpl userDetailsService;
 37→    private final PasswordEncoder passwordEncoder;
 38→    private final AuditLogService auditLogService;
 39→    private final UserRepository userRepository;
 40→
 41→    public AuthService(AuthenticationManager authenticationManager,
 42→                       JwtTokenProvider jwtTokenProvider,
 43→                       UserDetailsServiceImpl userDetailsService,
 44→                       PasswordEncoder passwordEncoder,
 45→                       AuditLogService auditLogService,
 46→                       UserRepository userRepository) {
 47→        this.authenticationManager = authenticationManager;
 48→        this.jwtTokenProvider = jwtTokenProvider;
 49→        this.userDetailsService = userDetailsService;
 50→        this.passwordEncoder = passwordEncoder;
 51→        this.auditLogService = auditLogService;
 52→        this.userRepository = userRepository;
 53→    }
 54→
 55→    @Transactional
 56→    public LoginResponse login(LoginRequest loginRequest) {
 57→        try {
 58→            Authentication authentication = authenticationManager.authenticate(
 59→                    new UsernamePasswordAuthenticationToken(
 60→                            loginRequest.getUsername(),
 61→                            loginRequest.getPassword()
 62→                    )
 63→            );
 64→
 65→            UserDetailsImpl userDetails = (UserDetailsImpl) authentication.getPrincipal();
 66→            String accessToken = jwtTokenProvider.generateAccessToken(authentication);
 67→            String refreshToken = jwtTokenProvider.generateRefreshToken(userDetails.getId());
 68→
 69→            // Update last login time
 70→            User user = userRepository.findById(userDetails.getId()).orElse(null);
 71→            if (user != null) {
 72→                user.setLastLoginAt(LocalDateTime.now());
 73→                userRepository.save(user);
 74→            }
 75→
 76→            List<String> roles = userDetails.getAuthorities().stream()
 77→                    .map(GrantedAuthority::getAuthority)
 78→                    .map(authority -> authority.startsWith("ROLE_") ? authority.substring(5) : authority)
 79→                    .collect(Collectors.toList());
 80→
 81→            List<String> permissions = List.copyOf(userDetails.getPermissions());
 82→
 83→            auditLogService.log(
 84→                    userDetails.getId(),
 85→                    AuditAction.LOGIN_SUCCESS,
 86→                    "User",
 87→                    userDetails.getId(),
 88→                    "User logged in successfully",
 89→                    null,
 90→                    null
 91→            );
 92→
 93→            logger.info("User '{}' logged in successfully", loginRequest.getUsername());
 94→
 95→            return LoginResponse.builder()
 96→                    .accessToken(accessToken)
 97→                    .refreshToken(refreshToken)
 98→                    .tokenType("Bearer")
 99→                    .expiresIn(jwtTokenProvider.getExpirationMs() / 1000)
100→                    .user(LoginResponse.UserInfo.builder()
101→                            .username(userDetails.getUsername())
102→                            .email(userDetails.getEmail())
103→                            .build())
104→                    .roles(roles)
105→                    .permissions(permissions)
106→                    .build();
107→
108→        } catch (AuthenticationException ex) {
109→            logger.warn("Login failed for username: {}", loginRequest.getUsername());
110→
111→            // Try to find user to log the failed attempt
112→            userRepository.findByUsername(loginRequest.getUsername()).ifPresent(user ->
113→                    auditLogService.log(
114→                            user.getId(),
115→                            AuditAction.LOGIN_FAILURE,
116→                            "User",
117→                            user.getId(),
118→                            "Login attempt failed: " + ex.getMessage(),
119→                            null,
120→                            null
121→                    )
122→            );
123→
124→            throw ex;
125→        }
126→    }
127→
128→    @Transactional(readOnly = true)
129→    public LoginResponse refreshToken(String refreshToken) {
130→        if (!jwtTokenProvider.validateToken(refreshToken)) {
131→            throw new IllegalArgumentException("Invalid or expired refresh token");
132→        }
133→
134→        Long userId = jwtTokenProvider.getUserIdFromToken(refreshToken);
135→        UserDetailsImpl userDetails = (UserDetailsImpl) userDetailsService.loadUserById(userId);
136→
137→        Authentication authentication = new UsernamePasswordAuthenticationToken(
138→                userDetails, null, userDetails.getAuthorities());
139→        String newAccessToken = jwtTokenProvider.generateAccessToken(authentication);
140→        String newRefreshToken = jwtTokenProvider.generateRefreshToken(userId);
141→
142→        List<String> roles = userDetails.getAuthorities().stream()
143→                .map(GrantedAuthority::getAuthority)
144→                .map(authority -> authority.startsWith("ROLE_") ? authority.substring(5) : authority)
145→                .collect(Collectors.toList());
146→
147→        List<String> permissions = List.copyOf(userDetails.getPermissions());
148→
149→        logger.debug("Access token refreshed for userId: {}", userId);
150→
151→        return LoginResponse.builder()
152→                .accessToken(newAccessToken)
153→                .refreshToken(newRefreshToken)
154→                .tokenType("Bearer")
155→                .expiresIn(jwtTokenProvider.getExpirationMs() / 1000)
156→                .user(LoginResponse.UserInfo.builder()
157→                        .username(userDetails.getUsername())
158→                        .email(userDetails.getEmail())
159→                        .build())
160→                .roles(roles)
161→                .permissions(permissions)
162→                .build();
163→    }
164→}
