  3→import com.scholarops.exception.ForbiddenException;
  4→import com.scholarops.exception.ResourceNotFoundException;
  5→import com.scholarops.model.dto.CrawlSourceRequest;
  6→import com.scholarops.model.entity.CrawlSourceProfile;
  7→import com.scholarops.model.entity.EncryptedSourceCredential;
  8→import com.scholarops.model.entity.User;
  9→import com.scholarops.model.enums.AuditAction;
 10→import com.scholarops.repository.CrawlSourceProfileRepository;
 11→import com.scholarops.repository.EncryptedSourceCredentialRepository;
 12→import com.scholarops.util.AesEncryptionUtil;
 13→import org.slf4j.Logger;
 14→import org.slf4j.LoggerFactory;
 15→import org.springframework.stereotype.Service;
 16→import org.springframework.transaction.annotation.Transactional;
 17→
 18→import java.util.List;
 19→
 20→@Service
 21→public class CrawlSourceService {
 22→
 23→    private static final Logger logger = LoggerFactory.getLogger(CrawlSourceService.class);
 24→
 25→    private final CrawlSourceProfileRepository crawlSourceProfileRepository;
 26→    private final EncryptedSourceCredentialRepository encryptedSourceCredentialRepository;
 27→    private final EncryptionService encryptionService;
 28→    private final AuditLogService auditLogService;
 29→
 30→    public CrawlSourceService(CrawlSourceProfileRepository crawlSourceProfileRepository,
 31→                               EncryptedSourceCredentialRepository encryptedSourceCredentialRepository,
 32→                               EncryptionService encryptionService,
 33→                               AuditLogService auditLogService) {
 34→        this.crawlSourceProfileRepository = crawlSourceProfileRepository;
 35→        this.encryptedSourceCredentialRepository = encryptedSourceCredentialRepository;
 36→        this.encryptionService = encryptionService;
 37→        this.auditLogService = auditLogService;
 38→    }
 39→
 40→    @Transactional
 41→    public CrawlSourceProfile createSource(CrawlSourceRequest request, Long userId) {
 42→        CrawlSourceProfile profile = CrawlSourceProfile.builder()
 43→                .name(request.getName())
 44→                .baseUrl(request.getBaseUrl())
 45→                .description(request.getDescription())
 46→                .rateLimitPerMinute(request.getRateLimitPerMinute() != null ? request.getRateLimitPerMinute() : 30)
 47→                .requiresAuth(request.getRequiresAuth() != null ? request.getRequiresAuth() : false)
 48→                .enabled(true)
 49→                .createdBy(User.builder().id(userId).build())
 50→                .build();
 51→
 52→        CrawlSourceProfile savedProfile = crawlSourceProfileRepository.save(profile);
 53→
 54→        // Encrypt and store credentials if provided
 55→        if (hasCredentials(request)) {
 56→            encryptAndSaveCredentials(savedProfile, request);
 57→        }
 58→
 59→        auditLogService.log(
 60→                userId,
 61→                AuditAction.CRAWL_SOURCE_CREATE,
 62→                "CrawlSourceProfile",
 63→                savedProfile.getId(),
 64→                "Created crawl source: " + savedProfile.getName(),
 65→                null,
 66→                null
 67→        );
 68→
 69→        logger.info("Crawl source '{}' created by userId={}", savedProfile.getName(), userId);
 70→        return savedProfile;
 71→    }
 72→
 73→    @Transactional
 74→    public CrawlSourceProfile updateSource(Long id, CrawlSourceRequest request, Long userId) {
 75→        CrawlSourceProfile profile = crawlSourceProfileRepository.findById(id)
 76→                .orElseThrow(() -> new ResourceNotFoundException("CrawlSourceProfile", "id", id));
 77→
 78→        verifyOwnership(profile, userId);
 79→
 80→        profile.setName(request.getName());
 81→        profile.setBaseUrl(request.getBaseUrl());
 82→        profile.setDescription(request.getDescription());
 83→        if (request.getRateLimitPerMinute() != null) {
 84→            profile.setRateLimitPerMinute(request.getRateLimitPerMinute());
 85→        }
 86→        if (request.getRequiresAuth() != null) {
 87→            profile.setRequiresAuth(request.getRequiresAuth());
 88→        }
 89→
 90→        // Re-encrypt credentials if provided
 91→        if (hasCredentials(request)) {
 92→            // Remove existing credentials if present
 93→            if (profile.getCredential() != null) {
 94→                encryptedSourceCredentialRepository.delete(profile.getCredential());
 95→                profile.setCredential(null);
 96→            }
 97→            encryptAndSaveCredentials(profile, request);
 98→        }
 99→
100→        CrawlSourceProfile updatedProfile = crawlSourceProfileRepository.save(profile);
101→
102→        auditLogService.log(
103→                userId,
104→                AuditAction.CRAWL_SOURCE_UPDATE,
105→                "CrawlSourceProfile",
106→                id,
107→                "Updated crawl source: " + profile.getName(),
108→                null,
109→                null
110→        );
111→
112→        logger.info("Crawl source '{}' updated by userId={}", profile.getName(), userId);
113→        return updatedProfile;
114→    }
115→
116→    @Transactional(readOnly = true)
117→    public CrawlSourceProfile getSource(Long id, Long userId) {
118→        CrawlSourceProfile profile = crawlSourceProfileRepository.findById(id)
119→                .orElseThrow(() -> new ResourceNotFoundException("CrawlSourceProfile", "id", id));
120→
121→        verifyOwnership(profile, userId);
122→
123→        // Credentials are masked by not exposing the credential entity fields directly.
124→        // The credential object is available on the entity but callers should not
125→        // serialize encrypted data. Controllers should handle masking at the DTO layer.
126→        return profile;
127→    }
128→
129→    @Transactional(readOnly = true)
130→    public List<CrawlSourceProfile> listSources(Long userId) {
131→        return crawlSourceProfileRepository.findByCreatedById(userId);
132→    }
133→
134→    @Transactional
135→    public void deleteSource(Long id, Long userId) {
136→        CrawlSourceProfile profile = crawlSourceProfileRepository.findById(id)
137→                .orElseThrow(() -> new ResourceNotFoundException("CrawlSourceProfile", "id", id));
138→
139→        verifyOwnership(profile, userId);
140→
141→        String name = profile.getName();
142→        crawlSourceProfileRepository.delete(profile);
143→
144→        auditLogService.log(
145→                userId,
146→                AuditAction.CRAWL_SOURCE_DELETE,
147→                "CrawlSourceProfile",
148→                id,
149→                "Deleted crawl source: " + name,
150→                null,
151→                null
152→        );
153→
154→        logger.info("Crawl source '{}' deleted by userId={}", name, userId);
155→    }
156→
157→    private void verifyOwnership(CrawlSourceProfile profile, Long userId) {
158→        if (!profile.getCreatedBy().getId().equals(userId)) {
159→            throw new ForbiddenException("You do not have permission to access this crawl source");
160→        }
161→    }
162→
163→    private boolean hasCredentials(CrawlSourceRequest request) {
164→        return (request.getUsername() != null && !request.getUsername().isBlank())
165→                || (request.getPassword() != null && !request.getPassword().isBlank())
166→                || (request.getApiKey() != null && !request.getApiKey().isBlank());
167→    }
168→
169→    private void encryptAndSaveCredentials(CrawlSourceProfile profile, CrawlSourceRequest request) {
170→        // Use a single IV for all credential fields of this source
171→        byte[] iv = null;
172→        byte[] encryptedUsername = null;
173→        byte[] encryptedPassword = null;
174→        byte[] encryptedApiKey = null;
175→
176→        if (request.getUsername() != null && !request.getUsername().isBlank()) {
177→            AesEncryptionUtil.EncryptedData data = encryptionService.encrypt(request.getUsername());
178→            encryptedUsername = data.getCiphertext();
179→            iv = data.getIv();
180→        }
181→
182→        if (request.getPassword() != null && !request.getPassword().isBlank()) {
183→            AesEncryptionUtil.EncryptedData data = encryptionService.encrypt(request.getPassword());
184→            encryptedPassword = data.getCiphertext();
185→            if (iv == null) {
186→                iv = data.getIv();
187→            }
188→        }
189→
190→        if (request.getApiKey() != null && !request.getApiKey().isBlank()) {
191→            AesEncryptionUtil.EncryptedData data = encryptionService.encrypt(request.getApiKey());
192→            encryptedApiKey = data.getCiphertext();
193→            if (iv == null) {
194→                iv = data.getIv();
195→            }
196→        }
197→
198→        if (iv != null) {
199→            EncryptedSourceCredential credential = EncryptedSourceCredential.builder()
200→                    .sourceProfile(profile)
201→                    .encryptedUsername(encryptedUsername)
202→                    .encryptedPassword(encryptedPassword)
203→                    .encryptedApiKey(encryptedApiKey)
204→                    .encryptionIv(iv)
205→                    .build();
206→            encryptedSourceCredentialRepository.save(credential);
207→            profile.setCredential(credential);
208→        }
209→    }
210→}
