 1→import { ref, onUnmounted, watch } from 'vue'
 2→
 3→export function useAutosave<T>(
 4→  saveFn: (data: T) => Promise<void>,
 5→  intervalMs = 15000
 6→) {
 7→  const isDirty = ref(false)
 8→  const isSaving = ref(false)
 9→  const lastSavedAt = ref<Date | null>(null)
10→  const error = ref<string | null>(null)
11→  let timer: ReturnType<typeof setInterval> | null = null
12→  let currentData: T | null = null
13→
14→  function markDirty(data: T) {
15→    currentData = data
16→    isDirty.value = true
17→    error.value = null
18→  }
19→
20→  async function save() {
21→    if (!isDirty.value || isSaving.value || currentData === null) return
22→
23→    isSaving.value = true
24→    error.value = null
25→
26→    try {
27→      await saveFn(currentData)
28→      isDirty.value = false
29→      lastSavedAt.value = new Date()
30→    } catch (e: any) {
31→      error.value = e.message || 'Autosave failed'
32→    } finally {
33→      isSaving.value = false
34→    }
35→  }
36→
37→  function start() {
38→    stop()
39→    timer = setInterval(() => {
40→      save()
41→    }, intervalMs)
42→  }
43→
44→  function stop() {
45→    if (timer) {
46→      clearInterval(timer)
47→      timer = null
48→    }
49→  }
50→
51→  function reset() {
52→    stop()
53→    isDirty.value = false
54→    isSaving.value = false
55→    lastSavedAt.value = null
56→    error.value = null
57→    currentData = null
58→  }
59→
60→  onUnmounted(() => {
61→    if (isDirty.value) {
62→      save()
63→    }
64→    stop()
65→  })
66→
67→  return {
68→    isDirty,
69→    isSaving,
70→    lastSavedAt,
71→    error,
72→    markDirty,
73→    save,
74→    start,
75→    stop,
76→    reset
77→  }
78→}
