120→<script setup lang="ts">
121→import { ref, computed, reactive, watch } from 'vue'
122→import type { Question } from '@/types/quiz'
123→import CountdownTimer from './CountdownTimer.vue'
124→
125→const props = defineProps<{
126→  quizTitle: string
127→  questions: Question[]
128→  timeRemaining: number
129→  showFeedback: boolean
130→  isSaving: boolean
131→  lastSaved: string
132→}>()
133→
134→const emit = defineEmits<{
135→  submit: []
136→  autosave: [answers: Record<number, { answerText?: string; selectedOption?: string }>, timeRemainingSeconds: number]
137→  timeExpired: []
138→}>()
139→
140→const currentIndex = ref(0)
141→const answers = reactive<Record<number, { answerText?: string; selectedOption?: string }>>({})
142→const liveRemaining = ref(props.timeRemaining)
143→
144→watch(() => props.timeRemaining, (t) => {
145→  liveRemaining.value = t
146→})
147→
148→function onTimerTick(remaining: number) {
149→  liveRemaining.value = remaining
150→}
151→
152→const currentQuestion = computed(() => props.questions[currentIndex.value] || null)
153→
154→const parsedOptions = computed(() => {
155→  if (!currentQuestion.value?.options) return []
156→  try {
157→    const parsed = JSON.parse(currentQuestion.value.options)
158→    return parsed.options || []
159→  } catch {
160→    return []
161→  }
162→})
163→
164→const answeredCount = computed(() => Object.keys(answers).length)
165→const progressPercent = computed(() => props.questions.length > 0 ? (answeredCount.value / props.questions.length) * 100 : 0)
166→
167→const feedback = computed(() => {
168→  if (!currentQuestion.value || !props.showFeedback) return null
169→  const answer = answers[currentQuestion.value.id]
170→  if (!answer) return null
171→  const isCorrect = answer.selectedOption === currentQuestion.value.correctAnswer ||
172→    answer.answerText === currentQuestion.value.correctAnswer
173→  return { isCorrect }
174→})
175→
176→function selectOption(questionId: number, option: string) {
177→  answers[questionId] = { ...answers[questionId], selectedOption: option }
178→  triggerAutosave()
179→}
180→
181→function setAnswerText(questionId: number, text: string) {
182→  answers[questionId] = { ...answers[questionId], answerText: text }
183→  triggerAutosave()
184→}
185→
186→function prevQuestion() {
187→  if (currentIndex.value > 0) currentIndex.value--
188→}
189→
190→function nextQuestion() {
191→  if (currentIndex.value < props.questions.length - 1) currentIndex.value++
192→}
193→
194→let autosaveTimer: ReturnType<typeof setTimeout> | null = null
195→function triggerAutosave() {
196→  if (autosaveTimer) clearTimeout(autosaveTimer)
197→  autosaveTimer = setTimeout(() => {
198→    emit('autosave', { ...answers }, liveRemaining.value)
199→  }, 3000)
200→}
201→
202→function handleTimeExpired() {
203→  emit('timeExpired')
204→}
205→</script>
