 69→<script setup lang="ts">
 70→import { ref, computed } from 'vue'
 71→import type { Schedule, LockedPeriod } from '@/types/schedule'
 72→import SessionBlock from './SessionBlock.vue'
 73→
 74→const props = defineProps<{
 75→  sessions: Schedule[]
 76→  lockedPeriods: LockedPeriod[]
 77→  undoStack: any[]
 78→  redoStack: any[]
 79→}>()
 80→
 81→const emit = defineEmits<{
 82→  merge: []
 83→  split: []
 84→  undo: []
 85→  redo: []
 86→  selectSession: [session: Schedule]
 87→  slotClick: [dayOfWeek: number, hour: number]
 88→  moveSession: [sessionId: number, newDay: number, newHour: number]
 89→}>()
 90→
 91→const conflictError = ref('')
 92→
 93→const canUndo = computed(() => props.undoStack.length > 0)
 94→const canRedo = computed(() => props.redoStack.length > 0)
 95→
 96→const days = [
 97→  { index: 1, name: 'Monday' },
 98→  { index: 2, name: 'Tuesday' },
 99→  { index: 3, name: 'Wednesday' },
100→  { index: 4, name: 'Thursday' },
101→  { index: 5, name: 'Friday' },
102→  { index: 6, name: 'Saturday' },
103→  { index: 0, name: 'Sunday' },
104→]
105→
106→const timeSlots = Array.from({ length: 14 }, (_, i) => i + 7) // 7:00 to 20:00
107→
108→function formatHour(hour: number): string {
109→  const period = hour >= 12 ? 'PM' : 'AM'
110→  const displayHour = hour > 12 ? hour - 12 : hour === 0 ? 12 : hour
111→  return `${displayHour}:00 ${period}`
112→}
113→
114→function getSessionsForDay(dayOfWeek: number): Schedule[] {
115→  return props.sessions.filter(s => s.dayOfWeek === dayOfWeek)
116→}
117→
118→function parseHour(time: string): number {
119→  if (time.includes('T')) {
120→    const d = new Date(time)
121→    if (!Number.isNaN(d.getTime())) return d.getHours()
122→  }
123→  return parseInt(time.split(':')[0] || '0', 10)
124→}
125→
126→function parseDayOfWeek(time: string): number | null {
127→  if (!time.includes('T')) return null
128→  const d = new Date(time)
129→  if (Number.isNaN(d.getTime())) return null
130→  return d.getDay()
131→}
132→
133→function matchingLockedPeriod(dayOfWeek: number, hour: number): LockedPeriod | undefined {
134→  return props.lockedPeriods.find(lp => {
135→    const explicitDay = lp.dayOfWeek
136→    const derivedDay = parseDayOfWeek(lp.startTime)
137→    const dayMatches = explicitDay != null
138→      ? explicitDay === dayOfWeek
139→      : derivedDay != null
140→        ? derivedDay === dayOfWeek
141→        : true
142→
143→    if (!dayMatches) return false
144→
145→    const lpStart = parseHour(lp.startTime)
146→    const lpEnd = parseHour(lp.endTime)
147→    return hour >= lpStart && hour < lpEnd
148→  })
149→}
150→
151→function isLocked(dayOfWeek: number, hour: number): boolean {
152→  return matchingLockedPeriod(dayOfWeek, hour) != null
153→}
154→
155→function getLockedReason(dayOfWeek: number, hour: number): string {
156→  const lp = matchingLockedPeriod(dayOfWeek, hour)
157→  return lp?.reason || 'Locked period'
158→}
159→
160→function sessionStyle(session: Schedule) {
161→  const startHour = parseInt(session.startTime.split(':')[0])
162→  const startMin = parseInt(session.startTime.split(':')[1] || '0')
163→  const endHour = parseInt(session.endTime.split(':')[0])
164→  const endMin = parseInt(session.endTime.split(':')[1] || '0')
165→  const top = (startHour - 7 + startMin / 60) * 48
166→  const height = (endHour - startHour + (endMin - startMin) / 60) * 48
167→  return {
168→    top: `${top}px`,
169→    height: `${height}px`,
170→    backgroundColor: session.color || '#3b82f6',
171→  }
172→}
173→
174→function handleSlotClick(dayOfWeek: number, hour: number) {
175→  if (isLocked(dayOfWeek, hour)) return
176→  emit('slotClick', dayOfWeek, hour)
177→}
178→
179→function undo() { emit('undo') }
180→function redo() { emit('redo') }
181→
182→let draggedSession: Schedule | null = null
183→
184→function onDragStart(session: Schedule, event: DragEvent) {
185→  draggedSession = session
186→  if (event.dataTransfer) {
187→    event.dataTransfer.effectAllowed = 'move'
188→  }
189→}
190→
191→function onDragEnd() {
192→  draggedSession = null
193→}
194→
195→defineExpose({ setConflictError: (msg: string) => { conflictError.value = msg } })
196→</script>
