  5→public final class LanguageDetector {
  6→
  7→    private static final Map<String, Set<String>> COMMON_WORDS = new HashMap<>();
  8→    private static final String DEFAULT_LANGUAGE = "en";
  9→
 10→    static {
 11→        COMMON_WORDS.put("en", Set.of(
 12→                "the", "is", "and", "of", "to", "in", "it", "that", "was", "for",
 13→                "on", "are", "with", "as", "this", "have", "from", "be", "not", "but",
 14→                "had", "has", "his", "her", "they", "were", "been", "would", "which", "their"
 15→        ));
 16→        COMMON_WORDS.put("es", Set.of(
 17→                "de", "la", "que", "el", "en", "los", "del", "las", "con", "una",
 18→                "por", "no", "son", "para", "como", "pero", "sus", "fue", "esta", "todo",
 19→                "hay", "ser", "tiene", "este", "donde", "puede", "muy", "sin", "sobre", "entre"
 20→        ));
 21→        COMMON_WORDS.put("fr", Set.of(
 22→                "le", "de", "un", "est", "et", "en", "que", "une", "les", "des",
 23→                "pour", "pas", "dans", "sur", "qui", "par", "sont", "avec", "ce", "mais",
 24→                "elle", "nous", "vous", "leur", "cette", "tout", "ses", "aux", "aussi", "bien"
 25→        ));
 26→        COMMON_WORDS.put("de", Set.of(
 27→                "der", "die", "und", "den", "von", "ist", "des", "ein", "das", "auf",
 28→                "dem", "sich", "mit", "eine", "nicht", "als", "auch", "aus", "noch", "nach",
 29→                "wird", "bei", "wie", "nur", "oder", "aber", "vor", "zur", "bis", "mehr"
 30→        ));
 31→        COMMON_WORDS.put("pt", Set.of(
 32→                "de", "que", "os", "uma", "para", "com", "por", "mais", "foi", "como",
 33→                "mas", "das", "dos", "seu", "sua", "tem", "ser", "este", "isso", "esta",
 34→                "nos", "ela", "ele", "pelo", "muito", "eram", "pode", "entre", "sobre", "seus"
 35→        ));
 36→        COMMON_WORDS.put("ru", Set.of(
 37→                "\u0438", "\u0432", "\u043d\u0435", "\u043d\u0430", "\u044f", "\u0447\u0442\u043e",
 38→                "\u0442\u043e", "\u0431\u044b\u043b\u043e", "\u043e\u043d", "\u043a\u0430\u043a",
 39→                "\u0435\u0433\u043e", "\u044d\u0442\u043e", "\u043e\u043d\u0430", "\u043c\u044b",
 40→                "\u0441", "\u043f\u043e", "\u0432\u0441\u0435", "\u043e\u043d\u0438", "\u0431\u044b\u043b",
 41→                "\u043a", "\u043e\u0442", "\u043d\u043e", "\u0435\u0441\u0442\u044c",
 42→                "\u0437\u0430", "\u0438\u0437", "\u043f\u0440\u043e", "\u043d\u0435\u0442",
 43→                "\u0442\u0430\u043a", "\u0431\u044b\u043b\u0430", "\u0443\u0436\u0435"
 44→        ));
 45→    }
 46→
 47→    private LanguageDetector() {
 48→        // Utility class
 49→    }
 50→
 51→    /**
 52→     * Detects the language of the given text using character frequency analysis
 53→     * and common word detection.
 54→     *
 55→     * @param text the input text
 56→     * @return ISO 639-1 language code (en, es, fr, de, zh, ja, ko, pt, ru, ar)
 57→     */
 58→    public static String detect(String text) {
 59→        if (text == null || text.isBlank()) {
 60→            return DEFAULT_LANGUAGE;
 61→        }
 62→
 63→        String trimmed = text.trim();
 64→
 65→        // Character-based detection for CJK and special scripts
 66→        String scriptDetection = detectByScript(trimmed);
 67→        if (scriptDetection != null) {
 68→            return scriptDetection;
 69→        }
 70→
 71→        // Word-based detection for Latin/Cyrillic scripts
 72→        return detectByCommonWords(trimmed);
 73→    }
 74→
 75→    private static String detectByScript(String text) {
 76→        int cjkCount = 0;
 77→        int hiraganaKatakana = 0;
 78→        int hangul = 0;
 79→        int arabic = 0;
 80→        int cyrillic = 0;
 81→        int totalLetters = 0;
 82→
 83→        for (char c : text.toCharArray()) {
 84→            if (!Character.isLetterOrDigit(c) && !Character.isWhitespace(c)) {
 85→                continue;
 86→            }
 87→            if (Character.isLetter(c)) {
 88→                totalLetters++;
 89→            }
 90→
 91→            Character.UnicodeBlock block = Character.UnicodeBlock.of(c);
 92→
 93→            if (block == Character.UnicodeBlock.CJK_UNIFIED_IDEOGRAPHS
 94→                    || block == Character.UnicodeBlock.CJK_UNIFIED_IDEOGRAPHS_EXTENSION_A
 95→                    || block == Character.UnicodeBlock.CJK_UNIFIED_IDEOGRAPHS_EXTENSION_B
 96→                    || block == Character.UnicodeBlock.CJK_COMPATIBILITY_IDEOGRAPHS) {
 97→                cjkCount++;
 98→            } else if (block == Character.UnicodeBlock.HIRAGANA
 99→                    || block == Character.UnicodeBlock.KATAKANA
100→                    || block == Character.UnicodeBlock.KATAKANA_PHONETIC_EXTENSIONS) {
101→                hiraganaKatakana++;
102→            } else if (block == Character.UnicodeBlock.HANGUL_SYLLABLES
103→                    || block == Character.UnicodeBlock.HANGUL_JAMO
104→                    || block == Character.UnicodeBlock.HANGUL_COMPATIBILITY_JAMO) {
105→                hangul++;
106→            } else if (block == Character.UnicodeBlock.ARABIC
107→                    || block == Character.UnicodeBlock.ARABIC_SUPPLEMENT) {
108→                arabic++;
109→            } else if (block == Character.UnicodeBlock.CYRILLIC) {
110→                cyrillic++;
111→            }
112→        }
113→
114→        if (totalLetters == 0) {
115→            return null;
116→        }
117→
118→        double threshold = 0.3;
119→
120→        if ((double) hiraganaKatakana / totalLetters > threshold) {
121→            return "ja";
122→        }
123→        if ((double) hangul / totalLetters > threshold) {
124→            return "ko";
125→        }
126→        if ((double) arabic / totalLetters > threshold) {
127→            return "ar";
128→        }
129→        if ((double) cyrillic / totalLetters > threshold) {
130→            return "ru";
131→        }
132→        // CJK without kana/hangul is likely Chinese
133→        if ((double) cjkCount / totalLetters > threshold) {
134→            return "zh";
135→        }
136→
137→        return null;
138→    }
139→
140→    private static String detectByCommonWords(String text) {
141→        String[] words = text.toLowerCase().split("\\s+");
142→        Map<String, Integer> scores = new HashMap<>();
143→
144→        for (String word : words) {
145→            String cleaned = word.replaceAll("[^\\p{L}]", "");
146→            if (cleaned.isEmpty()) {
147→                continue;
148→            }
149→            for (Map.Entry<String, Set<String>> entry : COMMON_WORDS.entrySet()) {
150→                if (entry.getValue().contains(cleaned)) {
151→                    scores.merge(entry.getKey(), 1, Integer::sum);
152→                }
153→            }
154→        }
155→
156→        if (scores.isEmpty()) {
157→            return DEFAULT_LANGUAGE;
158→        }
159→
160→        return scores.entrySet().stream()
161→                .max(Map.Entry.comparingByValue())
162→                .map(Map.Entry::getKey)
163→                .orElse(DEFAULT_LANGUAGE);
164→    }
165→}
