  8→public final class TimestampNormalizer {
  9→
 10→    private static final List<DateTimeFormatter> DATE_TIME_FORMATTERS = List.of(
 11→            DateTimeFormatter.ISO_DATE_TIME,
 12→            DateTimeFormatter.ISO_INSTANT,
 13→            DateTimeFormatter.ISO_OFFSET_DATE_TIME,
 14→            DateTimeFormatter.ISO_ZONED_DATE_TIME,
 15→            DateTimeFormatter.ISO_LOCAL_DATE_TIME,
 16→            DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss"),
 17→            DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ssXXX"),
 18→            DateTimeFormatter.ofPattern("yyyy-MM-dd'T'HH:mm:ssXXX"),
 19→            DateTimeFormatter.ofPattern("MM/dd/yyyy HH:mm:ss"),
 20→            DateTimeFormatter.ofPattern("MM/dd/yyyy hh:mm:ss a"),
 21→            DateTimeFormatter.ofPattern("MM/dd/yyyy h:mm:ss a"),
 22→            DateTimeFormatter.ofPattern("M/d/yyyy HH:mm:ss"),
 23→            DateTimeFormatter.ofPattern("M/d/yyyy h:mm:ss a"),
 24→            DateTimeFormatter.ofPattern("MM-dd-yyyy HH:mm:ss"),
 25→            DateTimeFormatter.ofPattern("dd/MM/yyyy HH:mm:ss"),
 26→            DateTimeFormatter.ofPattern("yyyy/MM/dd HH:mm:ss"),
 27→            DateTimeFormatter.ofPattern("MMM dd, yyyy HH:mm:ss"),
 28→            DateTimeFormatter.ofPattern("MMM dd, yyyy hh:mm:ss a"),
 29→            DateTimeFormatter.ofPattern("MMMM dd, yyyy HH:mm:ss"),
 30→            DateTimeFormatter.ofPattern("yyyy-MM-dd"),
 31→            DateTimeFormatter.ofPattern("MM/dd/yyyy"),
 32→            DateTimeFormatter.ofPattern("M/d/yyyy")
 33→    );
 34→
 35→    private TimestampNormalizer() {
 36→        // Utility class
 37→    }
 38→
 39→    /**
 40→     * Normalizes a raw timestamp string to a LocalDateTime in the specified timezone.
 41→     *
 42→     * @param rawTimestamp    the raw timestamp string (ISO 8601, US format, or Unix epoch seconds/millis)
 43→     * @param targetTimezone  the target timezone ID (e.g. "America/New_York", "UTC")
 44→     * @return the normalized LocalDateTime in the target timezone
 45→     * @throws IllegalArgumentException if the timestamp cannot be parsed
 46→     */
 47→    public static LocalDateTime normalize(String rawTimestamp, String targetTimezone) {
 48→        if (rawTimestamp == null || rawTimestamp.isBlank()) {
 49→            throw new IllegalArgumentException("Timestamp cannot be null or blank");
 50→        }
 51→
 52→        ZoneId targetZone = ZoneId.of(targetTimezone);
 53→        String trimmed = rawTimestamp.trim();
 54→
 55→        // Try Unix timestamp (seconds or milliseconds)
 56→        if (trimmed.matches("^-?\\d{1,13}$")) {
 57→            long value = Long.parseLong(trimmed);
 58→            Instant instant;
 59→            if (Math.abs(value) > 1_000_000_000_000L) {
 60→                // Milliseconds
 61→                instant = Instant.ofEpochMilli(value);
 62→            } else {
 63→                // Seconds
 64→                instant = Instant.ofEpochSecond(value);
 65→            }
 66→            return instant.atZone(targetZone).toLocalDateTime();
 67→        }
 68→
 69→        // Try Unix timestamp with decimal (seconds.fraction)
 70→        if (trimmed.matches("^-?\\d{1,10}\\.\\d+$")) {
 71→            double seconds = Double.parseDouble(trimmed);
 72→            long epochSeconds = (long) seconds;
 73→            long nanos = (long) ((seconds - epochSeconds) * 1_000_000_000);
 74→            Instant instant = Instant.ofEpochSecond(epochSeconds, nanos);
 75→            return instant.atZone(targetZone).toLocalDateTime();
 76→        }
 77→
 78→        // Try each date-time formatter
 79→        for (DateTimeFormatter formatter : DATE_TIME_FORMATTERS) {
 80→            try {
 81→                // Try as ZonedDateTime first (has timezone info)
 82→                ZonedDateTime zdt = ZonedDateTime.parse(trimmed, formatter);
 83→                return zdt.withZoneSameInstant(targetZone).toLocalDateTime();
 84→            } catch (DateTimeParseException ignored) {
 85→                // Continue
 86→            }
 87→
 88→            try {
 89→                // Try as OffsetDateTime
 90→                OffsetDateTime odt = OffsetDateTime.parse(trimmed, formatter);
 91→                return odt.atZoneSameInstant(targetZone).toLocalDateTime();
 92→            } catch (DateTimeParseException ignored) {
 93→                // Continue
 94→            }
 95→
 96→            try {
 97→                // Try as LocalDateTime (no timezone info, assume UTC)
 98→                LocalDateTime ldt = LocalDateTime.parse(trimmed, formatter);
 99→                return ldt.atZone(ZoneOffset.UTC).withZoneSameInstant(targetZone).toLocalDateTime();
100→            } catch (DateTimeParseException ignored) {
101→                // Continue
102→            }
103→
104→            try {
105→                // Try as LocalDate (date only, set time to midnight)
106→                LocalDate ld = LocalDate.parse(trimmed, formatter);
107→                return ld.atStartOfDay(ZoneOffset.UTC).withZoneSameInstant(targetZone).toLocalDateTime();
108→            } catch (DateTimeParseException ignored) {
109→                // Continue
110→            }
111→        }
112→
113→        throw new IllegalArgumentException("Unable to parse timestamp: " + trimmed);
114→    }
115→}
