  8→public final class AddressNormalizer {
  9→
 10→    private static final Map<String, String> ABBREVIATIONS = new LinkedHashMap<>();
 11→    private static final Map<String, String> STATE_ABBREVIATIONS = new LinkedHashMap<>();
 12→
 13→    static {
