 97→        STATE_ABBREVIATIONS.put("DC", "District of Columbia");
 98→    }
 99→
100→    private AddressNormalizer() {
101→        // Utility class
102→    }
103→
104→    /**
105→     * Normalizes a raw US address string.
106→     * Expands common abbreviations and formats as: Street, City, State ZIP.
107→     *
108→     * @param rawAddress the raw address string
109→     * @return normalized address string
110→     */
111→    public static String normalize(String rawAddress) {
112→        if (rawAddress == null || rawAddress.isBlank()) {
113→            return "";
114→        }
115→
116→        String address = rawAddress.trim();
117→
118→        // Normalize multiple spaces
119→        address = address.replaceAll("\\s{2,}", " ");
120→
121→        // Expand street type and directional abbreviations
122→        for (Map.Entry<String, String> entry : ABBREVIATIONS.entrySet()) {
123→            address = address.replaceAll("(?i)" + entry.getKey(), entry.getValue());
124→        }
125→
126→        // Try to parse and reformat as: Street, City, State ZIP
127→        // Common patterns: "123 Main St, Springfield, IL 62701"
128→        // or "123 Main St Springfield IL 62701"
129→        Pattern zipPattern = Pattern.compile(
130→                "^(.+?),\\s*(.+?),\\s*([A-Za-z]{2})\\s+(\\d{5}(?:-\\d{4})?)$");
131→        Matcher matcher = zipPattern.matcher(address);
132→        if (matcher.matches()) {
133→            String street = matcher.group(1).trim();
134→            String city = matcher.group(2).trim();
135→            String stateCode = matcher.group(3).trim().toUpperCase();
136→            String zip = matcher.group(4).trim();
137→
138→            String stateName = STATE_ABBREVIATIONS.getOrDefault(stateCode, stateCode);
139→            return String.format("%s, %s, %s %s", street, city, stateName, zip);
140→        }
141→
142→        // Try pattern without commas: "123 Main St Springfield IL 62701"
143→        Pattern noCommaPattern = Pattern.compile(
144→                "^(\\d+.+?)\\s+([A-Z][a-z]+(?:\\s[A-Z][a-z]+)*)\\s+([A-Z]{2})\\s+(\\d{5}(?:-\\d{4})?)$");
145→        Matcher noCommaMatcher = noCommaPattern.matcher(address);
146→        if (noCommaMatcher.matches()) {
147→            String street = noCommaMatcher.group(1).trim();
148→            String city = noCommaMatcher.group(2).trim();
149→            String stateCode = noCommaMatcher.group(3).trim().toUpperCase();
150→            String zip = noCommaMatcher.group(4).trim();
151→
152→            String stateName = STATE_ABBREVIATIONS.getOrDefault(stateCode, stateCode);
153→            return String.format("%s, %s, %s %s", street, city, stateName, zip);
154→        }
155→
156→        // Return the abbreviation-expanded address if no pattern matched
157→        return address;
158→    }
159→}
