 1→package com.scholarops.service;
 2→
 3→import org.springframework.beans.factory.annotation.Value;
 4→import org.springframework.stereotype.Service;
 5→
 6→import java.util.concurrent.ConcurrentHashMap;
 7→import java.util.concurrent.atomic.AtomicLong;
 8→
 9→@Service
10→public class RateLimiterService {
11→    private final ConcurrentHashMap<Long, TokenBucket> buckets = new ConcurrentHashMap<>();
12→    private final int defaultRate;
13→
14→    public RateLimiterService(@Value("${scholarops.crawl.default-rate-limit-per-minute:30}") int defaultRate) {
15→        this.defaultRate = defaultRate;
16→    }
17→
18→    public boolean acquirePermit(Long sourceId, int ratePerMinute) {
19→        int rate = ratePerMinute > 0 ? ratePerMinute : defaultRate;
20→        TokenBucket bucket = buckets.computeIfAbsent(sourceId, k -> new TokenBucket(rate));
21→        return bucket.tryConsume();
22→    }
23→
24→    int getAvailableTokens(Long sourceId) {
25→        TokenBucket bucket = buckets.get(sourceId);
26→        if (bucket == null) {
27→            return 0;
28→        }
29→        return bucket.availableTokens();
30→    }
31→
32→    private static class TokenBucket {
33→        private final int maxTokens;
34→        private final AtomicLong tokens;
35→        private volatile long lastRefillNanos;
36→        private final double tokensPerNano;
37→
38→        TokenBucket(int tokensPerMinute) {
39→            this.maxTokens = tokensPerMinute;
40→            this.tokens = new AtomicLong(tokensPerMinute);
41→            this.lastRefillNanos = System.nanoTime();
42→            this.tokensPerNano = tokensPerMinute / 60_000_000_000.0;
43→        }
44→
45→        synchronized boolean tryConsume() {
46→            refill();
47→            if (tokens.get() > 0) { tokens.decrementAndGet(); return true; }
48→            return false;
49→        }
50→
51→        private void refill() {
52→            long now = System.nanoTime();
53→            long elapsed = now - lastRefillNanos;
54→            long newTokens = (long)(elapsed * tokensPerNano);
55→            if (newTokens > 0) {
56→                tokens.set(Math.min(maxTokens, tokens.get() + newTokens));
57→                lastRefillNanos = now;
58→            }
59→        }
60→
61→        synchronized int availableTokens() {
62→            refill();
63→            return (int) tokens.get();
64→        }
65→    }
66→}
