 22→@Component
 23→public class CrawlerEngine {
 24→
 25→    private static final Logger logger = LoggerFactory.getLogger(CrawlerEngine.class);
 26→
 27→    private final ExtractionPipeline extractionPipeline;
 28→    private final RateLimiter rateLimiter;
 29→    private final CrawlRunRepository crawlRunRepository;
 30→    private final ContentStandardizationService contentStandardizationService;
 31→
 32→    @Value("${scholarops.crawl.default-rate-limit-per-minute:30}")
 33→    private int defaultRateLimit;
 34→
 35→    public CrawlerEngine(ExtractionPipeline extractionPipeline,
 36→            CrawlRunRepository crawlRunRepository,
 37→            ContentStandardizationService contentStandardizationService) {
 38→        this.extractionPipeline = extractionPipeline;
 39→        this.rateLimiter = new RateLimiter(30);
 40→        this.crawlRunRepository = crawlRunRepository;
 41→        this.contentStandardizationService = contentStandardizationService;
 42→    }
 43→
 44→    @Async("crawlExecutor")
 45→    public void executeCrawl(CrawlRun run, CrawlSourceProfile source, CrawlRuleVersion ruleVersion) {
 46→        logger.info("Starting crawl run {} for source {}", run.getId(), source.getName());
 47→
 48→        run.setStatus("RUNNING");
 49→        run.setStartedAt(LocalDateTime.now());
 50→        crawlRunRepository.save(run);
 51→
 52→        int rateLimit = source.getRateLimitPerMinute() != null ? source.getRateLimitPerMinute() : defaultRateLimit;
 53→        List<String> errors = new ArrayList<>();
 54→        int crawled = 0;
 55→        int failed = 0;
 56→        int extracted = 0;
 57→
 58→        try {
 59→            String baseUrl = source.getBaseUrl();
 60→            List<String> pagesToCrawl = discoverPages(baseUrl);
 61→            run.setTotalPages(pagesToCrawl.size());
 62→            crawlRunRepository.save(run);
 63→
 64→            for (String pageUrl : pagesToCrawl) {
 65→                if ("CANCELLED".equals(run.getStatus())) {
 66→                    logger.info("Crawl run {} cancelled", run.getId());
 67→                    break;
 68→                }
 69→
 70→                while (!rateLimiter.tryAcquire(source.getId(), rateLimit)) {
 71→                    try {
 72→                        Thread.sleep(1000);
 73→                    } catch (InterruptedException e) {
 74→                        Thread.currentThread().interrupt();
 75→                        break;
 76→                    }
 77→                }
 78→
 79→                try {
 80→                    String content = fetchPage(pageUrl);
 81→                    Map<String, Object> data = extractionPipeline.execute(
 82→                            content,
 83→                            ruleVersion.getExtractionMethod(),
 84→                            ruleVersion.getRuleDefinition(),
 85→                            ruleVersion.getFieldMappings()
 86→                    );
 87→
 88→                    if (ruleVersion.getTypeValidations() != null) {
 89→                        data = extractionPipeline.validateTypes(data, ruleVersion.getTypeValidations());
 90→                    }
 91→
 92→                    if (!data.isEmpty()) {
 93→                        if (data.get("sourceUrl") == null) {
 94→                            data.put("sourceUrl", pageUrl);
 95→                        }
 96→                        contentStandardizationService.standardize(data, "UTC", run, source);
 97→                        extracted++;
 98→                    }
 99→                    crawled++;
100→                } catch (Exception e) {
101→                    failed++;
102→                    errors.add(pageUrl + ": " + e.getMessage());
103→                    logger.warn("Failed to crawl page {}: {}", pageUrl, e.getMessage());
104→                }
105→
106→                run.setPagesCrawled(crawled);
107→                run.setPagesFailed(failed);
108→                run.setItemsExtracted(extracted);
109→                crawlRunRepository.save(run);
110→            }
111→
112→            run.setStatus("COMPLETED");
113→        } catch (Exception e) {
114→            run.setStatus("FAILED");
115→            errors.add("Fatal error: " + e.getMessage());
116→            logger.error("Crawl run {} failed", run.getId(), e);
117→        }
118→
119→        run.setCompletedAt(LocalDateTime.now());
120→        run.setErrorLog(errors.isEmpty() ? null : String.join("\n", errors));
121→        crawlRunRepository.save(run);
122→    }
123→
124→    private List<String> discoverPages(String baseUrl) {
125→        List<String> pages = new ArrayList<>();
126→        pages.add(baseUrl);
127→        try {
128→            Document doc = Jsoup.connect(baseUrl)
129→                    .timeout(10000)
130→                    .userAgent("ScholarOps-Crawler/1.0")
131→                    .get();
132→            doc.select("a[href]").forEach(link -> {
133→                String href = link.absUrl("href");
134→                if (href.startsWith(baseUrl) && !pages.contains(href)) {
135→                    pages.add(href);
136→                }
137→            });
138→        } catch (IOException e) {
139→            logger.warn("Could not discover pages from {}: {}", baseUrl, e.getMessage());
140→        }
141→        return pages;
142→    }
143→
144→    private String fetchPage(String url) throws IOException {
145→        return Jsoup.connect(url)
146→                .timeout(15000)
147→                .userAgent("ScholarOps-Crawler/1.0")
148→                .get()
149→                .html();
150→    }
151→}
