  saving.value = true
  try {
    gradingState.value = await gradeItem(id, payload.score, payload.feedback)
  } catch (e: any) {
    error.value = e.response?.data?.error || 'Failed to save grade'
  } finally {
    saving.value = false
  }
}
</script>
