    const page = data.data
    permissionEntries.value = page?.content || []
    permissionTotal.value = page?.totalElements || 0
  } catch (e) {
    permissionEntries.value = []
  } finally {
    permissionLoading.value = false
  }
}

onMounted(loadAuditLogs)
</script>

