  1→package com.scholarops.security;
  2→
  3→import io.jsonwebtoken.*;
  4→import io.jsonwebtoken.security.Keys;
  5→import org.slf4j.Logger;
  6→import org.slf4j.LoggerFactory;
  7→import org.springframework.beans.factory.annotation.Value;
  8→import org.springframework.security.core.Authentication;
  9→import org.springframework.security.core.GrantedAuthority;
 10→import org.springframework.stereotype.Component;
 11→
 12→import javax.crypto.SecretKey;
 13→import java.util.Base64;
 14→import java.util.Date;
 15→import java.util.Set;
 16→import java.util.concurrent.ConcurrentHashMap;
 17→import java.util.stream.Collectors;
 18→
 19→@Component
 20→public class JwtTokenProvider {
 21→
 22→    private static final Logger logger = LoggerFactory.getLogger(JwtTokenProvider.class);
 23→
 24→    private final SecretKey key;
 25→    private final long jwtExpirationMs;
 26→    private final long refreshExpirationMs;
 27→    private final Set<String> blacklistedTokens = ConcurrentHashMap.newKeySet();
 28→
 29→    public JwtTokenProvider(
 30→            @Value("${scholarops.jwt.secret}") String jwtSecret,
 31→            @Value("${scholarops.jwt.expiration-ms}") long jwtExpirationMs,
 32→            @Value("${scholarops.jwt.refresh-expiration-ms}") long refreshExpirationMs) {
 33→        byte[] keyBytes = Base64.getDecoder().decode(jwtSecret);
 34→        this.key = Keys.hmacShaKeyFor(keyBytes);
 35→        this.jwtExpirationMs = jwtExpirationMs;
 36→        this.refreshExpirationMs = refreshExpirationMs;
 37→    }
 38→
 39→    public String generateAccessToken(Authentication authentication) {
 40→        UserDetailsImpl userDetails = (UserDetailsImpl) authentication.getPrincipal();
 41→        Date now = new Date();
 42→        Date expiryDate = new Date(now.getTime() + jwtExpirationMs);
 43→
 44→        String roles = userDetails.getAuthorities().stream()
 45→                .map(GrantedAuthority::getAuthority)
 46→                .collect(Collectors.joining(","));
 47→
 48→        return Jwts.builder()
 49→                .subject(userDetails.getId().toString())
 50→                .claim("username", userDetails.getUsername())
 51→                .claim("roles", roles)
 52→                .issuedAt(now)
 53→                .expiration(expiryDate)
 54→                .signWith(key)
 55→                .compact();
 56→    }
 57→
 58→    public String generateRefreshToken(Long userId) {
 59→        Date now = new Date();
 60→        Date expiryDate = new Date(now.getTime() + refreshExpirationMs);
 61→
 62→        return Jwts.builder()
 63→                .subject(userId.toString())
 64→                .claim("type", "refresh")
 65→                .issuedAt(now)
 66→                .expiration(expiryDate)
 67→                .signWith(key)
 68→                .compact();
 69→    }
 70→
 71→    public Long getUserIdFromToken(String token) {
 72→        Claims claims = Jwts.parser()
 73→                .verifyWith(key)
 74→                .build()
 75→                .parseSignedClaims(token)
 76→                .getPayload();
 77→        return Long.parseLong(claims.getSubject());
 78→    }
 79→
 80→    public String getUsernameFromToken(String token) {
 81→        Claims claims = Jwts.parser()
 82→                .verifyWith(key)
 83→                .build()
 84→                .parseSignedClaims(token)
 85→                .getPayload();
 86→        return claims.get("username", String.class);
 87→    }
 88→
 89→    public boolean validateToken(String token) {
 90→        try {
 91→            if (blacklistedTokens.contains(token)) {
 92→                logger.warn("Token has been blacklisted");
 93→                return false;
 94→            }
 95→            Jwts.parser().verifyWith(key).build().parseSignedClaims(token);
 96→            return true;
 97→        } catch (MalformedJwtException e) {
 98→            logger.warn("Invalid JWT token");
 99→        } catch (ExpiredJwtException e) {
100→            logger.warn("Expired JWT token");
101→        } catch (UnsupportedJwtException e) {
102→            logger.warn("Unsupported JWT token");
103→        } catch (IllegalArgumentException e) {
104→            logger.warn("JWT claims string is empty");
105→        }
106→        return false;
107→    }
108→
109→    public void blacklistToken(String token) {
110→        if (token != null && !token.isBlank()) {
111→            blacklistedTokens.add(token);
112→        }
113→    }
114→
115→    public long getExpirationMs() {
116→        return jwtExpirationMs;
117→    }
118→}
