 17→import java.util.List;
 18→
 19→@Service
 20→public class GradingWorkflowService {
 21→    private final GradingStateRepository gradingStateRepository;
 22→    private final RubricScoreRepository rubricScoreRepository;
 23→    private final SubmissionAnswerRepository answerRepository;
 24→    private final AuditLogService auditLogService;
 25→
 26→    public GradingWorkflowService(GradingStateRepository gradingStateRepository,
 27→            RubricScoreRepository rubricScoreRepository, SubmissionAnswerRepository answerRepository,
 28→            AuditLogService auditLogService) {
 29→        this.gradingStateRepository = gradingStateRepository;
 30→        this.rubricScoreRepository = rubricScoreRepository;
 31→        this.answerRepository = answerRepository;
 32→        this.auditLogService = auditLogService;
 33→    }
 34→
 35→    @Transactional
 36→    public void routeToQueue(SubmissionAnswer answer) {
 37→        GradingState state = GradingState.builder()
 38→                .submissionAnswer(answer).status("PENDING").build();
 39→        gradingStateRepository.save(state);
 40→    }
 41→
 42→    public Page<GradingState> getGradingQueue(Pageable pageable, String status) {
 43→        return gradingStateRepository.findByStatus(status, pageable);
 44→    }
 45→
 46→    public GradingState getGradingState(Long id) {
 47→        return gradingStateRepository.findById(id)
 48→                .orElseThrow(() -> new ResourceNotFoundException("Grading state not found: " + id));
 49→    }
 50→
 51→    public GradingState getGradingStateForGrader(Long id, Long graderId) {
 52→        GradingState state = getGradingState(id);
 53→        if (state.getAssignedTo() != null && !state.getAssignedTo().getId().equals(graderId)) {
 54→            throw new ForbiddenException("Not authorized to access this grading state");
 55→        }
 56→        return state;
 57→    }
 58→
 59→    @Transactional
 60→    public GradingState gradeItem(Long gradingStateId, GradingRequest request, Long graderId) {
 61→        GradingState state = getGradingState(gradingStateId);
 62→        if (state.getAssignedTo() != null && !state.getAssignedTo().getId().equals(graderId)) {
 63→            throw new ForbiddenException("Not authorized to grade this submission");
 64→        }
 65→        state.setScore(request.getScore() != null ? BigDecimal.valueOf(request.getScore()) : null);
 66→        state.setFeedback(request.getFeedback());
 67→        state.setStatus("GRADED");
 68→        state.setGradedAt(LocalDateTime.now());
 69→
 70→        SubmissionAnswer answer = state.getSubmissionAnswer();
 71→        answer.setScore(request.getScore() != null ? BigDecimal.valueOf(request.getScore()) : null);
 72→        answer.setGradedAt(LocalDateTime.now());
 73→        answerRepository.save(answer);
 74→
 75→        auditLogService.log(graderId, AuditAction.GRADING_SUBMIT, "GradingState", gradingStateId,
 76→                "Graded submission answer", null, null);
 77→        return gradingStateRepository.save(state);
 78→    }
 79→
 80→    @Transactional
 81→    public GradingState addRubricScores(Long gradingStateId, List<RubricScoreRequest> rubricScores, Long graderId) {
 82→        GradingState state = getGradingState(gradingStateId);
 83→        if (state.getAssignedTo() != null && !state.getAssignedTo().getId().equals(graderId)) {
 84→            throw new ForbiddenException("Not authorized to grade this submission");
 85→        }
 86→        if (rubricScores == null || rubricScores.isEmpty()) {
 87→            throw new IllegalArgumentException("Rubric scores are mandatory for subjective grading");
 88→        }
 89→
 90→        BigDecimal totalAwarded = BigDecimal.ZERO;
 91→        for (RubricScoreRequest scoreReq : rubricScores) {
 92→            RubricScore rubric = RubricScore.builder()
 93→                    .gradingState(state)
 94→                    .criterionName(scoreReq.getCriterionName())
 95→                    .maxScore(BigDecimal.valueOf(scoreReq.getMaxScore()))
 96→                    .awardedScore(BigDecimal.valueOf(scoreReq.getAwardedScore()))
 97→                    .comment(scoreReq.getComment())
 98→                    .build();
 99→            rubricScoreRepository.save(rubric);
100→            totalAwarded = totalAwarded.add(BigDecimal.valueOf(scoreReq.getAwardedScore()));
101→        }
102→
103→        state.setScore(totalAwarded);
104→        state.setStatus("GRADED");
105→        state.setGradedAt(LocalDateTime.now());
106→
107→        SubmissionAnswer answer = state.getSubmissionAnswer();
108→        answer.setScore(totalAwarded);
109→        answer.setGradedAt(LocalDateTime.now());
110→        answerRepository.save(answer);
111→
112→        auditLogService.log(graderId, AuditAction.GRADING_SUBMIT, "GradingState", gradingStateId,
113→                "Added rubric scores", null, null);
114→        return gradingStateRepository.save(state);
115→    }
116→}
