142→    public Map<String, Object> getFeedback(Long submissionId, Long studentId) {
143→        Submission submission = getOwnSubmission(submissionId, studentId);
144→        if (!"GRADED".equals(submission.getStatus()) && !"RELEASED".equals(submission.getStatus())) {
145→            throw new ForbiddenException("Feedback is not yet available for this submission");
146→        }
147→        Map<String, Object> feedback = new HashMap<>();
148→        feedback.put("submissionId", submissionId);
149→        feedback.put("status", submission.getStatus());
150→        feedback.put("totalScore", submission.getTotalScore());
151→        feedback.put("maxScore", submission.getMaxScore());
152→        List<Map<String, Object>> sanitizedAnswers = new ArrayList<>();
153→        for (SubmissionAnswer answer : submission.getAnswers()) {
154→            Map<String, Object> answerMap = new HashMap<>();
155→            answerMap.put("questionId", answer.getQuestion().getId());
156→            answerMap.put("answerText", answer.getAnswerText());
157→            answerMap.put("selectedOption", answer.getSelectedOption());
158→            answerMap.put("score", answer.getScore());
159→            answerMap.put("isCorrect", answer.getIsCorrect());
