  2→
  3→import com.scholarops.model.entity.CrawlRun;
  4→import com.scholarops.model.entity.CrawlRuleVersion;
  5→import com.scholarops.model.entity.CrawlSourceProfile;
  6→import com.scholarops.repository.CrawlRunRepository;
  7→import com.scholarops.service.ContentStandardizationService;
  8→import com.scholarops.service.RateLimiterService;
  9→import org.jsoup.Jsoup;
 10→import org.jsoup.nodes.Document;
 11→import org.slf4j.Logger;
 12→import org.slf4j.LoggerFactory;
 13→import org.springframework.beans.factory.annotation.Value;
 14→import org.springframework.scheduling.annotation.Async;
 15→import org.springframework.stereotype.Component;
 16→
 17→import java.io.IOException;
 18→import java.time.LocalDateTime;
 19→import java.util.ArrayList;
 20→import java.util.List;
 21→import java.util.Map;
 22→
 23→@Component
 24→public class CrawlerEngine {
 25→
 26→    private static final Logger logger = LoggerFactory.getLogger(CrawlerEngine.class);
 27→
 28→    private final ExtractionPipeline extractionPipeline;
 29→    private final RateLimiterService rateLimiterService;
 30→    private final CrawlRunRepository crawlRunRepository;
 31→    private final ContentStandardizationService contentStandardizationService;
 32→
 33→    @Value("${scholarops.crawl.default-rate-limit-per-minute:30}")
 34→    private int defaultRateLimit;
 35→
 36→    public CrawlerEngine(ExtractionPipeline extractionPipeline,
 37→            CrawlRunRepository crawlRunRepository,
 38→            ContentStandardizationService contentStandardizationService,
 39→            RateLimiterService rateLimiterService) {
 40→        this.extractionPipeline = extractionPipeline;
 41→        this.rateLimiterService = rateLimiterService;
 42→        this.crawlRunRepository = crawlRunRepository;
 43→        this.contentStandardizationService = contentStandardizationService;
 44→    }
 45→
 46→    @Async("crawlExecutor")
 47→    public void executeCrawl(CrawlRun run, CrawlSourceProfile source, CrawlRuleVersion ruleVersion) {
 48→        logger.info("Starting crawl run {} for source {}", run.getId(), source.getName());
 49→
 50→        run.setStatus("RUNNING");
 51→        run.setStartedAt(LocalDateTime.now());
 52→        crawlRunRepository.save(run);
 53→
 54→        int rateLimit = source.getRateLimitPerMinute() != null ? source.getRateLimitPerMinute() : defaultRateLimit;
 55→        List<String> errors = new ArrayList<>();
 56→        int crawled = 0;
 57→        int failed = 0;
 58→        int extracted = 0;
 59→
 60→        try {
 61→            String baseUrl = source.getBaseUrl();
 62→            List<String> pagesToCrawl = discoverPages(baseUrl);
 63→            run.setTotalPages(pagesToCrawl.size());
 64→            crawlRunRepository.save(run);
 65→
 66→            for (String pageUrl : pagesToCrawl) {
 67→                if ("CANCELLED".equals(run.getStatus())) {
 68→                    logger.info("Crawl run {} cancelled", run.getId());
 69→                    break;
 70→                }
 71→
 72→                while (!rateLimiterService.acquirePermit(source.getId(), rateLimit)) {
 73→                    try {
 74→                        Thread.sleep(1000);
 75→                    } catch (InterruptedException e) {
 76→                        Thread.currentThread().interrupt();
 77→                        break;
 78→                    }
 79→                }
 80→
 81→                try {
 82→                    String content = fetchPage(pageUrl);
 83→                    Map<String, Object> data = extractionPipeline.execute(
 84→                            content,
 85→                            ruleVersion.getExtractionMethod(),
 86→                            ruleVersion.getRuleDefinition(),
 87→                            ruleVersion.getFieldMappings()
 88→                    );
 89→
 90→                    if (ruleVersion.getTypeValidations() != null) {
 91→                        data = extractionPipeline.validateTypes(data, ruleVersion.getTypeValidations());
 92→                    }
 93→
 94→                    if (!data.isEmpty()) {
 95→                        if (data.get("sourceUrl") == null) {
 96→                            data.put("sourceUrl", pageUrl);
 97→                        }
 98→                        contentStandardizationService.standardize(data, "UTC", run, source);
 99→                        extracted++;
100→                    }
101→                    crawled++;
102→                } catch (Exception e) {
103→                    failed++;
104→                    errors.add(pageUrl + ": " + e.getMessage());
105→                    logger.warn("Failed to crawl page {}: {}", pageUrl, e.getMessage());
106→                }
107→
108→                run.setPagesCrawled(crawled);
109→                run.setPagesFailed(failed);
110→                run.setItemsExtracted(extracted);
111→                crawlRunRepository.save(run);
112→            }
113→
114→            run.setStatus("COMPLETED");
115→        } catch (Exception e) {
116→            run.setStatus("FAILED");
117→            errors.add("Fatal error: " + e.getMessage());
118→            logger.error("Crawl run {} failed", run.getId(), e);
119→        }
120→
121→        run.setCompletedAt(LocalDateTime.now());
122→        run.setErrorLog(errors.isEmpty() ? null : String.join("\n", errors));
123→        crawlRunRepository.save(run);
124→    }
125→
126→    private List<String> discoverPages(String baseUrl) {
127→        List<String> pages = new ArrayList<>();
128→        pages.add(baseUrl);
129→        try {
130→            Document doc = Jsoup.connect(baseUrl)
131→                    .timeout(10000)
132→                    .userAgent("ScholarOps-Crawler/1.0")
133→                    .get();
134→            doc.select("a[href]").forEach(link -> {
135→                String href = link.absUrl("href");
136→                if (href.startsWith(baseUrl) && !pages.contains(href)) {
137→                    pages.add(href);
138→                }
139→            });
140→        } catch (IOException e) {
141→            logger.warn("Could not discover pages from {}: {}", baseUrl, e.getMessage());
142→        }
143→        return pages;
144→    }
145→
146→    private String fetchPage(String url) throws IOException {
147→        return Jsoup.connect(url)
148→                .timeout(15000)
149→                .userAgent("ScholarOps-Crawler/1.0")
150→                .get()
151→                .html();
152→    }
153→}
