154→                .orElseThrow(() -> new ResourceNotFoundException("CrawlSourceProfile", "id", id));
155→
156→        verifyOwnership(profile, userId);
157→
158→        String name = profile.getName();
159→        crawlSourceProfileRepository.delete(profile);
160→
161→        auditLogService.log(
162→                userId,
163→                AuditAction.CRAWL_SOURCE_DELETE,
164→                "CrawlSourceProfile",
165→                id,
166→                "Deleted crawl source: " + name,
167→                null,
168→                null
169→        );
170→
171→        logger.info("Crawl source '{}' deleted by userId={}", name, userId);
172→    }
173→
174→    private void verifyOwnership(CrawlSourceProfile profile, Long userId) {
175→        if (!profile.getCreatedBy().getId().equals(userId)) {
176→            throw new ForbiddenException("You do not have permission to access this crawl source");
177→        }
178→    }
179→
180→    private boolean hasCredentials(CrawlSourceRequest request) {
181→        return (request.getUsername() != null && !request.getUsername().isBlank())
182→                || (request.getPassword() != null && !request.getPassword().isBlank())
183→                || (request.getApiKey() != null && !request.getApiKey().isBlank());
184→    }
185→
186→    private void encryptAndSaveCredentials(CrawlSourceProfile profile, CrawlSourceRequest request) {
187→        // Use a single IV for all credential fields of this source
188→        byte[] iv = null;
189→        byte[] encryptedUsername = null;
190→        byte[] encryptedPassword = null;
191→        byte[] encryptedApiKey = null;
192→
193→        if (request.getUsername() != null && !request.getUsername().isBlank()) {
194→            AesEncryptionUtil.EncryptedData data = encryptionService.encrypt(request.getUsername());
195→            encryptedUsername = data.getCiphertext();
196→            iv = data.getIv();
197→        }
198→
199→        if (request.getPassword() != null && !request.getPassword().isBlank()) {
200→            AesEncryptionUtil.EncryptedData data = encryptionService.encrypt(request.getPassword());
201→            encryptedPassword = data.getCiphertext();
202→            if (iv == null) {
203→                iv = data.getIv();
204→            }
205→        }
206→
207→        if (request.getApiKey() != null && !request.getApiKey().isBlank()) {
208→            AesEncryptionUtil.EncryptedData data = encryptionService.encrypt(request.getApiKey());
209→            encryptedApiKey = data.getCiphertext();
210→            if (iv == null) {
211→                iv = data.getIv();
212→            }
213→        }
214→
215→        if (iv != null) {
216→            EncryptedSourceCredential credential = EncryptedSourceCredential.builder()
217→                    .sourceProfile(profile)
218→                    .encryptedUsername(encryptedUsername)
219→                    .encryptedPassword(encryptedPassword)
220→                    .encryptedApiKey(encryptedApiKey)
221→                    .encryptionIv(iv)
222→                    .build();
223→            encryptedSourceCredentialRepository.save(credential);
224→            profile.setCredential(credential);
225→        }
226→    }
227→}
