  1→package com.scholarops.service;
  2→
  3→import com.scholarops.exception.ResourceNotFoundException;
  4→import com.scholarops.crawler.CrawlerEngine;
  5→import com.scholarops.model.dto.CrawlRunRequest;
  6→import com.scholarops.model.entity.CrawlRuleVersion;
  7→import com.scholarops.model.entity.CrawlRun;
  8→import com.scholarops.model.entity.CrawlSourceProfile;
  9→import com.scholarops.model.entity.User;
 10→import com.scholarops.model.enums.AuditAction;
 11→import com.scholarops.repository.CrawlRunRepository;
 12→import com.scholarops.repository.CrawlRuleVersionRepository;
 13→import com.scholarops.repository.CrawlSourceProfileRepository;
 14→import org.slf4j.Logger;
 15→import org.slf4j.LoggerFactory;
 16→import org.springframework.data.domain.Page;
 17→import org.springframework.data.domain.Pageable;
 18→import org.springframework.stereotype.Service;
 19→import org.springframework.transaction.annotation.Transactional;
 20→
 21→import java.time.LocalDateTime;
 22→
 23→@Service
 24→public class CrawlRunService {
 25→
 26→    private static final Logger logger = LoggerFactory.getLogger(CrawlRunService.class);
 27→
 28→    private final CrawlRunRepository crawlRunRepository;
 29→    private final CrawlSourceProfileRepository crawlSourceProfileRepository;
 30→    private final CrawlRuleVersionRepository crawlRuleVersionRepository;
 31→    private final AuditLogService auditLogService;
 32→    private final CrawlerEngine crawlerEngine;
 33→
 34→    public CrawlRunService(CrawlRunRepository crawlRunRepository,
 35→                            CrawlSourceProfileRepository crawlSourceProfileRepository,
 36→                            CrawlRuleVersionRepository crawlRuleVersionRepository,
 37→                            AuditLogService auditLogService,
 38→                            CrawlerEngine crawlerEngine) {
 39→        this.crawlRunRepository = crawlRunRepository;
 40→        this.crawlSourceProfileRepository = crawlSourceProfileRepository;
 41→        this.crawlRuleVersionRepository = crawlRuleVersionRepository;
 42→        this.auditLogService = auditLogService;
 43→        this.crawlerEngine = crawlerEngine;
 44→    }
 45→
 46→    @Transactional
 47→    public CrawlRun startRun(CrawlRunRequest request, Long userId) {
 48→        CrawlSourceProfile sourceProfile = crawlSourceProfileRepository.findById(request.getSourceProfileId())
 49→                .orElseThrow(() -> new ResourceNotFoundException("CrawlSourceProfile", "id", request.getSourceProfileId()));
 50→
 51→        CrawlRuleVersion ruleVersion = crawlRuleVersionRepository.findById(request.getRuleVersionId())
 52→                .orElseThrow(() -> new ResourceNotFoundException("CrawlRuleVersion", "id", request.getRuleVersionId()));
 53→
 54→        CrawlRun run = CrawlRun.builder()
 55→                .sourceProfile(sourceProfile)
 56→                .ruleVersion(ruleVersion)
 57→                .status("PENDING")
 58→                .totalPages(0)
 59→                .pagesCrawled(0)
 60→                .pagesFailed(0)
 61→                .itemsExtracted(0)
 62→                .initiatedBy(User.builder().id(userId).build())
 63→                .build();
 64→
 65→        CrawlRun savedRun = crawlRunRepository.save(run);
 66→
 67→        // Launch real async crawl through crawler engine.
 68→        crawlerEngine.executeCrawl(savedRun, sourceProfile, ruleVersion);
 69→
 70→        auditLogService.log(
 71→                userId,
 72→                AuditAction.CRAWL_RUN_START,
 73→                "CrawlRun",
 74→                savedRun.getId(),
 75→                "Started crawl run for source: " + sourceProfile.getName(),
 76→                null,
 77→                null
 78→        );
 79→
 80→        logger.info("Crawl run {} started for source '{}' by userId={}", savedRun.getId(), sourceProfile.getName(), userId);
 81→        return savedRun;
 82→    }
 83→
 84→    @Transactional(readOnly = true)
 85→    public CrawlRun getRun(Long id) {
 86→        return crawlRunRepository.findById(id)
 87→                .orElseThrow(() -> new ResourceNotFoundException("CrawlRun", "id", id));
 88→    }
 89→
 90→    @Transactional(readOnly = true)
 91→    public Page<CrawlRun> listRuns(Pageable pageable, Long sourceId) {
 92→        if (sourceId != null) {
 93→            return crawlRunRepository.findBySourceProfileId(sourceId, pageable);
 94→        }
 95→        return crawlRunRepository.findAll(pageable);
 96→    }
 97→
 98→    @Transactional
 99→    public CrawlRun cancelRun(Long id, Long userId) {
100→        CrawlRun run = crawlRunRepository.findById(id)
101→                .orElseThrow(() -> new ResourceNotFoundException("CrawlRun", "id", id));
102→
103→        if ("COMPLETED".equals(run.getStatus()) || "CANCELLED".equals(run.getStatus()) || "FAILED".equals(run.getStatus())) {
104→            throw new IllegalStateException("Cannot cancel a run that is already " + run.getStatus());
105→        }
106→
107→        run.setStatus("CANCELLED");
108→        run.setCompletedAt(LocalDateTime.now());
109→        CrawlRun cancelled = crawlRunRepository.save(run);
110→
111→        auditLogService.log(
112→                userId,
113→                AuditAction.CRAWL_RUN_CANCEL,
114→                "CrawlRun",
115→                id,
116→                "Cancelled crawl run",
117→                null,
118→                null
119→        );
120→
121→        logger.info("Crawl run {} cancelled by userId={}", id, userId);
122→        return cancelled;
123→    }
124→}
